两种bitcpy的实现方式

1. 显示数据bits#define HALF_WORD   uint16_t#define WORD        uint32_tvoid showBits(void* d, int len) &#123;    int bytes = len / 8;    unsigned char* p = (unsigned char*)d;    for (int i = 0; i &lt; bytes; i++) &#123;        unsigned char tmp = 0x80;        for (int j = 0; j &lt; 8; j++) &#123;            if (tmp &amp; *p)                printf(&quot;1&quot;);            else                printf(&quot;0&quot;);            tmp &gt;&gt;= 1;        &#125;        printf(&quot; &quot;);        ++p;    &#125;    printf(&quot;\n&quot;);&#125;

2. bitcpy 算术方式拷贝方式是从单个字节的低位开始拷贝，进位式拷贝。
int bitcopy(void* to, unsigned int tOfs, int tCnt, const void* from, unsigned int fOfs, int fCnt) &#123;    int BitsOfHalfWord = sizeof(HALF_WORD) * 8;    // align data and offset to HALF_WORD    to = (void*)((intptr_t)to + (tOfs / BitsOfHalfWord) * sizeof(HALF_WORD));    from = (void*)((intptr_t)from + (fOfs / BitsOfHalfWord) * sizeof(HALF_WORD));    fOfs %= BitsOfHalfWord;    tOfs %= BitsOfHalfWord;    int NbrOfCopiedBits = 0, bCnt = (fCnt &lt; tCnt) ? fCnt : tCnt;    WORD rMask, wMask;    WORD temp, * _to = (WORD*)to, * _from = (WORD*)from;    while (bCnt &gt; 0) &#123;        // update counter        int BitsToCopy = (bCnt &lt; BitsOfHalfWord) ? bCnt : BitsOfHalfWord;        bCnt -= BitsToCopy;        NbrOfCopiedBits += BitsToCopy;        // mask reading from &#x27;_from&#x27; and mask writing to &#x27;_to&#x27;        rMask = (((WORD)-1) &lt;&lt; fOfs) ^ (((WORD)-1) &lt;&lt; (fOfs + BitsToCopy));        wMask = (((WORD)-1) &lt;&lt; tOfs) ^ (((WORD)-1) &lt;&lt; (tOfs + BitsToCopy));        showBits(&amp;rMask, 32);        showBits(&amp;wMask, 32);        temp = (*_from &amp; rMask) &gt;&gt; fOfs &lt;&lt; tOfs;        *_to &amp;= ~wMask;        *_to |= temp;        printf(&quot;%d bit(s) copied\n&quot;, BitsToCopy);        // increase data pointer if copy is not completed        if (BitsToCopy == BitsOfHalfWord) &#123;            _to = (WORD*)((intptr_t)_to + sizeof(HALF_WORD));            _from = (WORD*)((intptr_t)_from + sizeof(HALF_WORD));        &#125;        showBits(to, 64);    &#125;    return NbrOfCopiedBits;&#125;

3. bitcpy 物理方式物理左移
WORD shiftLeft(WORD w, int len) &#123;    unsigned char* s = (unsigned char*)&amp;w;    while (len--) &#123;        *(s) &lt;&lt;= 1;        for (int i = 1; i &lt; 4; i++) &#123;            if (*(s + i) == 0)                continue;            if (*(s + i) &amp; 0x80)                *(s + i - 1) |= 1;            *(s + i) &lt;&lt;= 1;        &#125;    &#125;    return w;&#125;
物理右移
WORD shiftRight(WORD w, int len) &#123;    unsigned char* s = (unsigned char*)&amp;w;    while (len--) &#123;        *(s+3) &gt;&gt;= 1;        for (int i = 2; i &gt;= 0; i--) &#123;            if (*(s + i) == 0)                continue;            if (*(s + i) &amp; 1)                *(s + i + 1) |= 0x80;            *(s + i) &gt;&gt;= 1;        &#125;    &#125;    return w;&#125;
拷贝方式是按照实际的物理bit位进行顺序拷贝的
int bitcpy(void* to, unsigned int tOfs, const void* from, unsigned int fOfs, int bCnt) &#123;    int BitsOfHalfWord = sizeof(HALF_WORD) * 8;    // 将数据和偏置对其“半字”    // 指针视为intptr_t，加1则前进一个Byte，且更安全（适用于将指针进行算术运算时使用）    to = (void*)((intptr_t)to + (tOfs / BitsOfHalfWord) * sizeof(HALF_WORD));    from = (void*)((intptr_t)from + (fOfs / BitsOfHalfWord) * sizeof(HALF_WORD));    fOfs %= BitsOfHalfWord;    tOfs %= BitsOfHalfWord;    int NbrOfCopiedBits = 0;    WORD rMask, wMask;    WORD temp;    WORD *_to = (WORD*)to;    WORD *_from = (WORD*)from;    while (bCnt &gt; 0) &#123;        // 更新        int BitsToCopy = (bCnt &lt; BitsOfHalfWord) ? bCnt : BitsOfHalfWord;        bCnt -= BitsToCopy;        NbrOfCopiedBits += BitsToCopy;        // 源与目标的遮罩        rMask = shiftRight((WORD)-1, fOfs) ^ shiftRight((WORD)-1, fOfs + BitsToCopy);        wMask = shiftRight((WORD)-1, tOfs) ^ shiftRight((WORD)-1, tOfs + BitsToCopy);        temp = (*_from &amp; rMask);        temp = shiftLeft(temp, fOfs);        temp = shiftRight(temp, tOfs);        *_to &amp;= ~wMask;	// 先清理此部分        *_to |= temp;	// 在“拷贝”进来        // 拷贝未完成情况下，跟进指针        if (BitsToCopy == BitsOfHalfWord) &#123;            _to = (WORD*)((intptr_t)_to + sizeof(HALF_WORD));            _from = (WORD*)((intptr_t)_from + sizeof(HALF_WORD));        &#125;    &#125;    return NbrOfCopiedBits;&#125;

函数介绍
lock_guard：锁定互斥锁后，生命周期结束后会自动释放，不需要手动解锁，也无法手动解锁
unique_lock：多数情况与上面一个可以相互替代，但是其更具功能性（付出一些代价）。unique_lock可以进行unlock操作，因此可以和条件变量搭配使用

多线程输出数字多个线程互斥输出: 0 1 2 3 4 5 6 ...
#include &lt;iostream&gt;#include &lt;vector&gt;#include &lt;thread&gt;#include &lt;mutex&gt;using namespace std;int idx = 0;mutex _mutex;void func(int n) &#123;	while (idx &lt; n) &#123; // 改成true一样的		lock_guard&lt;mutex&gt; tmp(_mutex);		if (idx &gt;= n) break; // 必须，否则多输出几个数才停		cout &lt;&lt; idx++ &lt;&lt; &quot; &quot;;	&#125;&#125;int main() &#123;	vector&lt;thread&gt; arr;	for (int i = 0; i &lt; 10; ++i)		arr.push_back(thread(func, 1000));	for (auto&amp; e : arr)		e.join();	return 0;&#125;
版本2
#include &lt;iostream&gt;#include &lt;vector&gt;#include &lt;thread&gt;#include &lt;mutex&gt;#include &lt;windows.h&gt;using namespace std;int idx = 0;mutex _mutex;void func(int n) &#123;	while (idx &lt; n) &#123;		lock_guard&lt;mutex&gt; tmp(_mutex);		if (idx &gt;= n) break;		cout &lt;&lt; idx++ &lt;&lt; &quot; &quot;;	&#125;&#125;int main() &#123;	vector&lt;thread&gt; arr;	for (int i = 0; i &lt; 10; ++i) &#123;		auto t = thread(func, 1000);        // 不需要join了		t.detach();        // 这里不能传入左值，会报错“尝试引用已删除的函数”        // 或者通过vector存放thread的指针的方式		arr.push_back(move(t));	&#125;	// 模拟其他操作，虽然detach后不需要join但是主线程结束后    // 子线程也会直接结束	Sleep(1000);	return 0;&#125;


多线程输出ABC多个线程互斥输出:
A B CA B CA B CA B C...
#include &lt;iostream&gt;#include &lt;thread&gt;#include &lt;mutex&gt;using namespace std;mutex _mutex;int step = 0;int stepNum = 0;void func1() &#123;	while (true) &#123;		lock_guard&lt;mutex&gt; tmp(_mutex);		if (stepNum == 30) break;		if (step % 3 == 0) &#123;			++step;			++stepNum;			cout &lt;&lt; &quot;A&quot; &lt;&lt; &quot; &quot;;		&#125;	&#125;&#125;void func2() &#123;	while (true) &#123;		lock_guard&lt;mutex&gt; tmp(_mutex);		if (stepNum == 30) break;		if (step % 3 == 1) &#123;			++step;			++stepNum;			cout &lt;&lt; &quot;B&quot; &lt;&lt; &quot; &quot;;		&#125;	&#125;&#125;void func3() &#123;	while (true) &#123;		lock_guard&lt;mutex&gt; tmp(_mutex);		if (stepNum == 30) break;		if (step % 3 == 2) &#123;			++step;			++stepNum;			cout &lt;&lt; &quot;C&quot; &lt;&lt; endl;		&#125;	&#125;&#125;int main() &#123;	thread t1(func1);	thread t2(func2);	thread t3(func3);	t1.join();	t2.join();	t3.join();	return 0;&#125;

条件变量#include &lt;iostream&gt;#include &lt;thread&gt;#include &lt;mutex&gt;#include &lt;windows.h&gt;#include &lt;condition_variable&gt;using namespace std;mutex _mutex;condition_variable cv;bool ready = false;// 最开始10个线程会在cv.wait处阻塞，并且会unlock _mutex。// 当cv.notify后，这十个线程便会以随机的顺序尝试lock _mutex继续向下执行void workers(int id) &#123;	unique_lock&lt;mutex&gt; ulck(_mutex); // 可以灵活unlock	while (ready == false) &#123;		cout &lt;&lt; &quot;here: &quot;&lt;&lt; id &lt;&lt; endl;		cv.wait(ulck); // 阻塞		// 其他操作...	&#125;	cout &lt;&lt; &quot;thread: &quot; &lt;&lt; id &lt;&lt; endl;&#125;void go() &#123;	unique_lock&lt;mutex&gt; ulck(_mutex);	ready = true;	cv.notify_all();&#125;int main() &#123;	thread mt[10];	for (int i = 0; i &lt; 10; ++i)		mt[i] = thread(workers, i);	cout &lt;&lt; &quot;10 threads ready to race...(already!)&quot; &lt;&lt; endl;	Sleep(50); // 确保前面的线程先到地方wait	go();	for (auto&amp; e : mt)		e.join();	return 0;&#125;

0. 说明
C++采用g++编译，C采用gcc编译。两者主要不同点是：C++编译考虑到函数重载，会将原函数“改名”（命名倾轧name mangling）；而在C中不存在重载，函数名不会变动。
g++和gcc可以兼容C++和C的编译方式，但是默认情况下g++采用C++编译方式；而gcc采用C的编译方式
注意：gcc编译C++文件时不会主动链接C++用到的库stdc++，需要手动指定链接选项-lstdc++
__cplusplus宏定义会在编译cpp文件以及用C++的方式编译时被包含，因此用gcc编译.cpp文件或者g++编译.c、.cpp文件都会有这个宏
之所以用条件判断，因为gcc不认识extern &quot;C&quot;，直接编译会报错

1. C++调用C只需要声明时包含extern &quot;C&quot;即可。下面的代码中，func.h可以不动，在main.cpp调用时，直接extern &quot;C&quot; int func(int, int)也是可以的。只需要让编译器按照C的方式编译，不要改动函数名即可正确链接的函数符号。
// func.h 不论.c还是.cpp文件调用，都不会出错#ifndef FUNC_H#define FUNC_H#ifdef __cplusplusextern &quot;C&quot; &#123;#endif // __cplusplusint func(int, int);#ifdef __cplusplus&#125;#endif // __cplusplus#endif

// func.c#include &quot;func.h&quot;int func(int a, int b) &#123;	return a + b;&#125;

// main.cpp#include &lt;iostream&gt;#include &quot;func.h&quot;int main() &#123;	std::cout &lt;&lt; func(1, 3) &lt;&lt; std::endl;&#125;

2. C调用C++C调用C++稍微麻烦点，遇到类函数和重载函数往往需要嵌套一层，详细如下。
2.1. 普通函数// func.h#ifndef FUNC_H#define FUNC_H#ifdef __cplusplusextern &quot;C&quot; &#123;#endif // __cplusplusvoid func();#ifdef __cplusplus&#125;#endif#endif

// func.cpp#include &quot;func.h&quot;#include &lt;iostream&gt;void func() &#123;	std::cout &lt;&lt; &quot;void func()&quot; &lt;&lt; std::endl;&#125;

// main.c#include &quot;func.h&quot;int main() &#123;	func();&#125;


2.2. 重载函数// func.h#ifndef ADAPTER_H#define ADAPTER_H#ifdef __cplusplusextern &quot;C&quot; &#123;#endif // __cplusplusvoid func_();void func_i(int);#ifdef __cplusplus&#125;#endif#endif

// func.cpp#include &quot;func.h&quot;#include &lt;iostream&gt;void func() &#123;	std::cout &lt;&lt; &quot;void func()&quot; &lt;&lt; std::endl;&#125;void func(int a) &#123;	std::cout &lt;&lt; &quot;void func(int)&quot; &lt;&lt; std::endl;&#125;// adaptervoid func_() &#123;	func();&#125;void func_i(int a) &#123;	func(a);&#125;

// main.c#include &quot;func.h&quot;int main() &#123;	func_();	func_i(1);&#125;

2.3. 类函数// Circle.h#ifndef CIRCLE_H#define CIRCLE_Hclass Circle &#123;	double radius;public:	Circle(double r) :radius(r) &#123;&#125;	double getArea();&#125;;#endif

// Circle.cpp#include &quot;Circle.h&quot;double Circle::getArea() &#123;	return 3.1415926 * radius * radius;&#125;

核心文件（adapter.h），此代码必须在C ++和C文件中都可以编译。
// adapter.h#ifndef ADAPTER_H#define ADAPTER_H#ifdef __cplusplusextern &quot;C&quot; &#123;#endif // __cplusplusvoid* Circle_new(double);double Circle_getAea(void*);void Circle_detete(void*);#ifdef __cplusplus&#125;#endif#endif

// adapter.cpp#include &quot;adapter.h&quot;#include &quot;Circle.h&quot;void* Circle_new(double r) &#123;	Circle *p = new Circle(r);	return (void*)p;&#125;double Circle_getAea(void* p) &#123;	return ((Circle*)p)-&gt;getArea();&#125;void Circle_detete(void* p) &#123;	Circle* cp = (Circle*)p;	delete cp;&#125;

// main.c#include &lt;stdio.h&gt;#include &quot;adapter.h&quot;int main() &#123;	void* p = Circle_new(1);	printf(&quot;%lf\n&quot;, Circle_getAea(p));	Circle_detete(p);&#125;

3. 参考
c语言和c++的相互调用
C语言中调用C＋＋
极简式从C调用C++类方法
C调用C++和C++调用C
C++与C的相互调用

问题新项目，在学习FairyGUI，看到官方Demo里的Window示例有这么一段代码
// 业务层BasicsMainprivate Window _winA; // 实例变量private Window _winB; // 实例变量private void PlayWindow()&#123;    GComponent obj = _demoObjects[&quot;Window&quot;];    obj.GetChild(&quot;n0&quot;).onClick.Add(() =&gt;    &#123;        if (_winA == null)            _winA = new Window1();        _winA.Show();    &#125;);    obj.GetChild(&quot;n1&quot;).onClick.Add(() =&gt;    &#123;        if (_winB == null)            _winB = new Window2();        _winB.Show();    &#125;);&#125;// FairyGUI.EventListener.cspublic void Add(EventCallback0 callback)&#123;    _bridge.Add(callback);&#125;// FairyGUI.EventBridge.csEventCallback0 _callback0;public void Add(EventCallback0 callback)&#123;    _callback0 -= callback;    _callback0 += callback;&#125;
这个PlayWindow函数是每次点击对应按钮都会调用的，但是里面的注册回调却用的匿名函数，虽然内部会先对委托进行解绑再绑定，但是匿名函数，怎敢断定两次调用传入的是同一个函数的？我立马嗅到一丝内存泄漏的异味，但是实际并没有发生。
验证噢，我知道了一定是编译器又在暗中帮忙，我立马打开的ILSpy打开对应程序集文件（Project&#x2F;Library&#x2F;ScriptAssemblis&#x2F;YourAssembly.dll）”，然后看到了编译器暗中做的事情：（记得取消勾选ILSpy视图&#x2F;选项里的“反编译匿名方法或lambda”，不然ILSpy会将内部细节优化掉，你只能看到传入的是lambda {}）
private void PlayWindow()&#123;    GComponent obj = _demoObjects[&quot;Window&quot;];    obj.GetChild(&quot;n0&quot;).onClick.Add(&lt;PlayWindow&gt;b__18_0);    obj.GetChild(&quot;n1&quot;).onClick.Add(&lt;PlayWindow&gt;b__18_1);&#125;[CompilerGenerated]private void &lt;PlayWindow&gt;b__18_0()&#123;    if (_winA == null)    &#123;        _winA = new Window1();    &#125;    _winA.Show();&#125;[CompilerGenerated]private void &lt;PlayWindow&gt;b__18_1()&#123;    if (_winB == null)    &#123;        _winB = new Window2();    &#125;    _winB.Show();&#125;
可以看到，对于这两个匿名函数的注册，编译器直接优化成了类的实例函数（因为匿名函数只捕获了实例变量），有了确定的地址！因此取消注册也能顺利完成。
脆弱实际使用过程中，这种方式需要被杜绝掉，因为假如，匿名函数捕获的不是当前上下文的实例变量，而是局部变量呢，我改了下代码：
private Window _winA;private Window _winB;private void PlayWindow()&#123;    int a = 1;    GComponent obj = _demoObjects[&quot;Window&quot;];    obj.GetChild(&quot;n0&quot;).onClick.Add(() =&gt;    &#123;        Debug.Log(a);        if (_winA == null)            _winA = new Window1();        _winA.Show();    &#125;);    obj.GetChild(&quot;n1&quot;).onClick.Add(() =&gt;    &#123;        if (_winB == null)            _winB = new Window2();        _winB.Show();    &#125;);&#125;
刷新下ILSpy：
private void PlayWindow()&#123;    &lt;&gt;c__DisplayClass18_0 &lt;&gt;c__DisplayClass18_ = new &lt;&gt;c__DisplayClass18_0();    &lt;&gt;c__DisplayClass18_.&lt;&gt;4__this = this;    &lt;&gt;c__DisplayClass18_.a = 1;    GComponent obj = _demoObjects[&quot;Window&quot;];    obj.GetChild(&quot;n0&quot;).onClick.Add(&lt;&gt;c__DisplayClass18_.&lt;PlayWindow&gt;b__0);    obj.GetChild(&quot;n1&quot;).onClick.Add(&lt;&gt;c__DisplayClass18_.&lt;PlayWindow&gt;b__1);&#125;[CompilerGenerated]private sealed class &lt;&gt;c__DisplayClass18_0&#123;    public int a;    public BasicsMain &lt;&gt;4__this;    internal void &lt;PlayWindow&gt;b__0()    &#123;        Debug.Log((object)a);        if (&lt;&gt;4__this._winA == null)        &#123;            &lt;&gt;4__this._winA = new Window1();        &#125;        &lt;&gt;4__this._winA.Show();    &#125;    internal void &lt;PlayWindow&gt;b__1()    &#123;        if (&lt;&gt;4__this._winB == null)        &#123;            &lt;&gt;4__this._winB = new Window2();        &#125;        &lt;&gt;4__this._winB.Show();    &#125;&#125;
这次编译器采用的策略是生成一个匿名类，将捕获的变量作为自身的实例变量，每次执行PlayWindow，都重新创建一个匿名类，这样传入的实例函数的target属于不同对象（委托的相等需满足target相等 + method相等），自然无法正确解绑，实测也是如此，发生了内存泄漏。
延展那如果，匿名函数内部不捕获任何变量呢？调用的改动如下，只在匿名函数内输出一条日志：
private Window _winA;private Window _winB;private void PlayWindow()&#123;    GComponent obj = _demoObjects[&quot;Window&quot;];    obj.GetChild(&quot;n0&quot;).onClick.Add(() =&gt;    &#123;        Debug.Log(&quot;a&quot;);    &#125;);    obj.GetChild(&quot;n1&quot;).onClick.Add(() =&gt;    &#123;        if (_winB == null)            _winB = new Window2();        _winB.Show();    &#125;);&#125;
刷新下ILSpy：
private void PlayWindow()&#123;    GComponent obj = _demoObjects[&quot;Window&quot;];    obj.GetChild(&quot;n0&quot;).onClick.Add(&lt;&gt;c.&lt;&gt;9__18_0 ?? (&lt;&gt;c.&lt;&gt;9__18_0 = &lt;&gt;c.&lt;&gt;9.&lt;PlayWindow&gt;b__18_0));    obj.GetChild(&quot;n1&quot;).onClick.Add(&lt;PlayWindow&gt;b__18_1);&#125;    [Serializable][CompilerGenerated]private sealed class &lt;&gt;c&#123;    // 不要在意，类种其他函数调用的匿名函数所生成的内容    public static readonly &lt;&gt;c &lt;&gt;9 = new &lt;&gt;c();    // 不要在意，类种其他函数调用的匿名函数所生成的内容    public static GTweenCallback1 &lt;&gt;9__11_0;    // 不要在意，类种其他函数调用的匿名函数所生成的内容    public static EventCallback0 &lt;&gt;9__12_0;    // 不要在意，类种其他函数调用的匿名函数所生成的内容    public static EventCallback1 &lt;&gt;9__13_0;    // here    public static EventCallback0 &lt;&gt;9__18_0;    // 不要在意，类种其他函数调用的匿名函数所生成的内容    internal void &lt;PlayGraph&gt;b__11_0(GTweener t)    &#123;        ((NGraphics)t.target).GetMeshFactory&lt;LineMesh&gt;().fillEnd = t.value.x;        ((NGraphics)t.target).SetMeshDirty();    &#125;    // 不要在意，类种其他函数调用的匿名函数所生成的内容    internal void &lt;PlayButton&gt;b__12_0()    &#123;        Debug.Log((object)&quot;click button&quot;);    &#125;    // 不要在意，类种其他函数调用的匿名函数所生成的内容    internal void &lt;PlayText&gt;b__13_0(EventContext context)    &#123;        GRichTextField t = context.sender as GRichTextField;        t.text = &quot;[img]ui://Basics/pet[/img][color=#FF0000]You click the link[/color]：&quot; + context.data;    &#125;    // here    internal void &lt;PlayWindow&gt;b__18_0()    &#123;        Debug.Log((object)&quot;a&quot;);    &#125;&#125;
可以看到，这时编译器依旧会生成一个匿名类+静态字段，并且还是一个单例类，匿名方法是该匿名单例类的实例方法，因此绑定和解绑的也都会是同一个委托，不会发生内存泄漏。
SharpLab与ILSpy反编译不同，SharpLab可以直接用Roslyn生成编译后的C#，或许会看到更详细的信息，针对类似情况的匿名函数，做了如下模拟：
1. 委托是静态方法class B&#123;    private A a = new();    public void Test()    &#123;        a.Bind(Del);        a.Fire();    &#125;        static void Del()    &#123;        Console.WriteLine(1);    &#125;&#125;class A&#123;    private Action act;    public void Bind(Action ac)    &#123;        act -= ac;        act += ac;    &#125;    public void Fire()    &#123;        act?.Invoke();    &#125;&#125;
生成的结果和之前反编译的有所不同，这次生成的是静态匿名类+静态字段来指向我的静态方法（上文ILSpy是单例类+静态字段），虽然形式上不一样，但是结果没什么区别，反正不捕获。
