结果如下，看起来就跟没进行任何处理一样，这样一来，就不会每次调用都new一个Action了。为什么编译器不这样做呢，因为会隐式引入额外内存大小？委托如果只传递一次确实是负优化了哈哈。
[NullableContext(1)][Nullable(0)]internal class B&#123;    private A a = new A();    private readonly Action _p;    public B()    &#123;        _p = new Action(Del);    &#125;    public void Test()    &#123;        a.Bind(_p);        a.Fire();    &#125;    private void Del()    &#123;        Console.WriteLine(1);    &#125;&#125;

结论
不要用匿名方法绑定事件，很容易内存泄漏
委托是静态方法，直接传递
委托是实例方法，如果可能多次绑定，可以考虑存一个实例委托变量而不是直接传入实例方法，用以优化GC。

470 用 Rand7() 实现 Rand10()1. 拒绝采样在解LC-470前先介绍一道拒绝采样的经典问题：利用频率近似概率的方式求出 $\pi$ 的值。在 $1\times1$ 的方块内随机坐标采样，记录落入以原点为圆心，半径为1的 $\frac{1}{4}$ 圆内的次数。
由 $\frac{1}{4}\pi r^2 &#x3D; \frac{cnt}{N}$ 可得 $\pi &#x3D; \frac{4\times cnt}{N\times r^2}$ ，由于 $r&#x3D;1$ ，所以 $\pi &#x3D; \frac{4\times cnt}{N}$
int main() &#123;    srand((unsigned)time(0)); // time(0)表示从1970到现在的秒数    int N = (int)1e7, cnt = 0;    for (int i = 0; i &lt; N; i++) &#123;        double a = (1.0 * rand() / RAND_MAX); // 除以RAND_MAX归一化0~1        double b = (1.0 * rand() / RAND_MAX);        if (a * a + b * b &lt; 1.0) cnt++; // 落入1/4圆则加一    &#125;    printf(&quot;%lf&quot;, (4.0 * cnt) / N);    return 0;&#125;

2. LC-470 Rand7生成Rand10力扣高赞题解
(rand_X() - 1) × Y + rand_Y() &#x3D;&#x3D;&gt; 可以等概率的生成[1, X * Y]范围的随机数
class Solution &#123;public:    int rand10() &#123;        while(true)&#123;            // 等概率生成[1,49]范围的随机数            int num = (rand7()-1)*7 + rand7();            // 拒绝采样，并返回[1,10]范围的随机数            if(num &lt;= 40) return num % 10 + 1;        &#125;    &#125;&#125;;

1. 124 二叉树中的最大路径和1.1 两个递归的笨方法class Solution &#123;public:    int ans = INT_MIN;    int core(TreeNode* root) &#123; // 找到以root为起点，深入向下的最大路径一条线（分叉只走一条）        if(!root) return 0;        int lv = core(root-&gt;left);        int rv = core(root-&gt;right);        int res = max(max(lv, rv), 0) + root-&gt;val;        return res;    &#125;        void recursion(TreeNode* root)&#123; // 遍历树中每个结点，尝试寻找本题答案的“起点根”        if(!root) return;        recursion(root-&gt;left);        recursion(root-&gt;right);        int lv = core(root-&gt;left); // 以左孩子为起点的“线”        int rv = core(root-&gt;right); // 以右孩子为起点的“线”        if(lv &lt; 0) lv = 0;        if(rv &lt; 0) rv = 0;        ans = max(ans, lv + rv + root-&gt;val);    &#125;        int maxPathSum(TreeNode* root) &#123;        recursion(root);        return ans;    &#125;&#125;;

1.2 一个递归的好方法class Solution &#123;public:    int ans = INT_MIN;    int core(TreeNode* root) &#123;        if(!root) return 0;                // 递归计算左右子节点的最大贡献值        // 只有在最大贡献值大于 0 时，才会选取对应子节点        int lv = max(core(root-&gt;left), 0);        int rv = max(core(root-&gt;right), 0);                // 节点的最大路径和取决于该节点的值与该节点的左右子节点的最大贡献值        int ifAnsRoot = root-&gt;val + lv + rv;        ans = max(ans, ifAnsRoot);                // 返回        return max(lv, rv) + root-&gt;val;    &#125;        int maxPathSum(TreeNode* root) &#123;        core(root);        return ans;    &#125;&#125;;

2. 543 二叉树的直径这些问题都有共性：递归主线依旧，所求是副产物2.1 两个递归的笨方法class Solution &#123;public:    int core(TreeNode* root)&#123;        if(!root) return 0;        int l = core(root-&gt;left);        int r = core(root-&gt;right);        return max(l, r) + 1;    &#125;        int diameterOfBinaryTree(TreeNode* root) &#123;        if(!root) return 0;        int l = diameterOfBinaryTree(root-&gt;left);        int r = diameterOfBinaryTree(root-&gt;right);        int m = core(root-&gt;left) + core(root-&gt;right);        return max(m, max(l, r));    &#125;&#125;;

2.2 一个递归的好方法// 递归主线还是算高度，直径是 [副产品]class Solution &#123;public:    int res = 0;    int core(TreeNode* root)&#123; // 给定根节点，计算最长深度节点数        if(!root) return 0;        int l = core(root-&gt;left); // 左儿子为根的子树的深度        int r = core(root-&gt;right); // 右儿子为根的子树的深度        res = max(res, l + r); // 在这里更新res，不用+1，因为路径长度是总结点长度-1        return max(l, r) + 1; // 返回该节点为根的子树的最长深度节点数    &#125;        int diameterOfBinaryTree(TreeNode* root) &#123;        if(!root) return 0;        core(root);        return res;    &#125;&#125;;

一、简单排序
定义：对于下标$i&lt;j$，如果$A[i]&gt;A[j]$，则称$(i,j)$是一对逆序对（inversion）
定理：任意$N$个不同元素组成的序列平均具有$N(N-1)&#x2F;4$个逆序对。
定理：任何仅以交换相邻两元素来排序的算法，其平均时间复杂度为$Ω(N^2)$

1. 冒泡排序
时间复杂度：$O(N^2)$
最好情况下的时间复杂度，有序$O(N)$
空间复杂度：$O(1)$
稳定（比较相等时，是不做交换的）
end标记可以提前结束
链表也可用
每次交换都会消除一对逆序对
如果$I$是逆序对的个数，时间复杂度是$O(N+I)$



void bubbleSort(vector&lt;int&gt;&amp; arr) &#123;    int n = arr.size();    for (int i = 0; i &lt; n - 1; ++i) &#123;        int end = 1;        for (int j = 0; j &lt; n - 1 - i; ++j) &#123;            if (arr[j] &gt; arr[j + 1])            &#123;                swap(arr[j], arr[j + 1]);                end = 0;            &#125;        &#125;        if (end)            break;    &#125;&#125;
// 47838ms for 10w elements(0~10w random)public static void BubbleSort&lt;T&gt;(IList&lt;T&gt; arr) where T : IComparable&lt;T&gt;&#123;    for (int last = arr.Count - 1; last &gt; 0; --last)    &#123;        var end = true;        for (int i = 0; i &lt; last; ++i)        &#123;            if (arr[i].CompareTo(arr[i+1])&gt;0)            &#123;                Swap(arr, i, i + 1);                end = false;            &#125;        &#125;        if (end)            break;    &#125;&#125;

2. 插入排序
时间复杂度：$O(N^2)$
最好情况下的时间复杂度，有序$O(N)$
空间复杂度：$O(1)$
稳定（比较相等时，是不做后移覆盖的）
冒泡需要swap，而这里是连续的后移覆盖，操作数更少
每次调整牌位都会消除一对逆序对
如果$I$是逆序对的个数，时间复杂度是$O(N+I)$


常被高级排序拿来搭配，小规模数据的最佳搭档（通常$N&lt;64$）

void insertSort(vector&lt;int&gt;&amp; arr) &#123;    int n = arr.size();    for (int i = 1; i &lt; n; ++i) &#123;        int cur = arr[i];        int j = i - 1;        for (; j &gt;= 0 &amp;&amp; arr[j] &gt; cur; --j)            arr[j + 1] = arr[j];        arr[j + 1] = cur;    &#125;&#125;

// 13514ms for 10w elements(0~10w random)public static void InsertSort&lt;T&gt;(IList&lt;T&gt; arr) where T : IComparable&lt;T&gt;&#123;    for (int i = 1; i &lt; arr.Count; ++i)    &#123;        var pre = i - 1;        var origin = arr[i];        for (; pre &gt;= 0; --pre)        &#123;            if (arr[pre].CompareTo(origin) &gt; 0)                arr[pre + 1] = arr[pre];            else                break;        &#125;        arr[pre + 1] = origin;    &#125;&#125;

2.1 插入排序思考插牌的时候，我们无法改变移动的次数，毕竟新的牌最终的位置是确定的。但是我们可以优化比较的次数：既然新的牌到来时，前面的牌都是有序的，那就可以通过二分查找进行优化。这样虽然移动次数是$O(N^2)$但是比较次会降为$O(NlogN)$。在对10w个数据的排序测试中，二分插入排序速度比普通插入排序快了接近一倍。

注意保证插入排序的稳定性，二分时是寻找最右侧的target，即相等时，是左侧指针移动

// 7588ms for 10w elements(0~10w random)public static void BinaryInsertSort&lt;T&gt;(IList&lt;T&gt; arr, int l, int r) where T : IComparable&lt;T&gt;&#123;    for (int i = l + 1; i &lt;= r; ++i)    &#123;        var origin = arr[i];        int bl = l, br = i - 1;        while (bl &lt;= br)        &#123;            int bm = (bl + br) &gt;&gt; 1;            // 相等时，是左侧指针移动            if (arr[bm].CompareTo(origin) &gt; 0)                br = bm - 1;            else                bl = bm + 1;        &#125;        for (int t = i; t &gt; bl; --t)            arr[t] = arr[t - 1];        arr[bl] = origin;    &#125;&#125;

3. 选择排序
最好&#x2F;最坏时间复杂度：$O(N^2)$
空间复杂度：$O(1)$
不稳定：交换打破稳定性，例如对[4a,4b,1]的排序。
若想选择排序稳定，需要开辟新的数组空间；或者进行大量移位操作（交换改成插入）；或者排序的是链表



算法伪代码void Selection_Sort(ElementType A[], int N) &#123;    // 其实外层循环N-1次就行了    for (int i = 0; i &lt; N; ++i) &#123;        /* 从A[i]到A[N-1]中找最小元，并将其位置赋给MinPosition */        MinPosition = ScanForMin(A, i, N-1);        /* 将未排序部分的最小元换到有序部分的最后位置 */        Swap(A[i], A[MinPosition]);    &#125;&#125;
// 29051ms for 10w elements(0~10w random)public static void SelectSort&lt;T&gt;(IList&lt;T&gt; arr) where T : IComparable&lt;T&gt;&#123;    for (int i = 0; i &lt; arr.Count - 1; ++i)    &#123;        var minPosition = i;        for (int j = i; j &lt; arr.Count; ++j)        &#123;            if (arr[j].CompareTo(arr[minPosition]) &lt; 0)                minPosition = j;        &#125;        if (i != minPosition)            Swap(arr, i, minPosition);    &#125;&#125;

二、高级排序4. 希尔排序（由插入排序进化而来）定义增量序列$D_M&gt;D_{M-1}&gt;…&gt;D_1 &#x3D; 1$，对每个$D_k$进行$D_k$间隔排序$(k &#x3D; M, M-1, …, 1)$。值得注意的是：“$D_k$间隔”有序的序列，在执行“$D_{k-1}$间隔”排序后，仍然保持“$D_k$间隔”有序。这是希尔排序的前提！增量元素的设计很重要，增量元素不互质，会导致小增量可能根本不起作用。

Hibbard增量序列：$D_k &#x3D; 2^k - 1$，相邻元素互质，最坏情况复杂度是$Θ(N^{\frac{3}{2}})$
时间复杂度：$O(N^{\frac{4}{3}})$~$O(N^{\frac{3}{2}})$复杂度非常难以估算
空间复杂度：$O(1)$
不稳定（与插入排序不同了，因为希尔是跳跃交换的）
下面两个C++实现都一样，唯一区别就是插入排序外循环里面i增加的形式，第一种分开实现，第二种合并了

4.1 实现1（Ugly）void shellSort(vector&lt;int&gt;&amp; arr) &#123;    int n = arr.size();    // 选择的增量序列是（2^k-1），可以跟随数组大小生成，但是为了简化算法代码，突出主题，在此固定长度了    static vector&lt;int&gt; incre = &#123; 1023, 511, 255, 127, 63, 31, 15, 7, 3, 1 &#125;;    for (int u = 0; u &lt;incre.size(); ++u) &#123; // 增量循环        int width = incre[u];        if (width &gt; n) continue;        for (int v = 0; v &lt; width; ++v) &#123; // 当前增量循环            for (int i = width + v; i &lt; n; i += width) &#123; // 插入排序外循环                int cur = arr[i];                int j = i - width;                for (; j &gt;= 0 &amp;&amp; arr[j] &gt; cur; j -= width) // 插入排序内循环                    arr[j + width] = arr[j];                arr[j + width] = cur;            &#125;        &#125;    &#125;&#125;

4.2 实现2（浙大陈姥姥代码）void shellSort(vector&lt;int&gt;&amp; arr) &#123;    int n = arr.size();    // 选择的增量序列是（2^k-1），可以跟随数组大小生成，但是为了简化算法代码，突出主题，在此固定长度了    static vector&lt;int&gt; incre = &#123; 1023, 511, 255, 127, 63, 31, 15, 7, 3, 1 &#125;;    for (int u = 0; u &lt; incre.size(); ++u) &#123; // 增量循环        int width = incre[u];        for (int i = width; i &lt; n; ++i) &#123; // 插入排序外循环            int cur = arr[i];            int j = i - width;            for (; j &gt;= 0 &amp;&amp; arr[j] &gt; cur; j -= width) // 插入排序内循环                arr[j + width] = arr[j];            arr[j + width] = cur;        &#125;    &#125;&#125;
4.3 C#实现（Good）// 44ms for 10w elements(0~10w random)public static int PowerOfTwoFloor(int n)&#123;    n |= (n &gt;&gt; 1);    n |= (n &gt;&gt; 2);    n |= (n &gt;&gt; 4);    n |= (n &gt;&gt; 8);    n |= (n &gt;&gt; 16);    return (n &gt;&gt; 1) + 1;&#125;public static void ShellSort&lt;T&gt;(IList&lt;T&gt; arr) where T : IComparable&lt;T&gt;&#123;    int power = PowerOfTwoFloor(arr.Count);    for (int delta = power - 1; delta &gt;= 1; delta = power - 1)    &#123;        // 第一张牌后，后续是++        for (int cur = delta; cur &lt; arr.Count; ++cur)        &#123;            var temp = arr[cur];            var pre = cur - delta;            // 往前探时，是delta跨步            for (; pre &gt;= 0; pre -= delta)            &#123;                if (arr[pre].CompareTo(temp) &gt; 0)                    arr[pre + delta] = arr[pre];                else                    break;            &#125;            arr[pre + delta] = temp;        &#125;        power &gt;&gt;= 1;    &#125;&#125;

5. 堆排序（由选择排序进化而来）
时间复杂度：$O(NlogN)$
空间复杂度：$O(1)$
不稳定（继承自选择排序）

5.1 C++实现void downMethod(vector&lt;int&gt;&amp; arr, int f, int sz) &#123;    int s = f * 2 + 1;    int cur = arr[f];    while(s &lt; sz)&#123;        if (s + 1 &lt; sz &amp;&amp; arr[s] &lt; arr[s + 1]) // 兄弟值大，让位            ++s;        if (arr[s] &lt;= cur) break; // 父亲值大，镇压        arr[f] = arr[s]; // 儿子值大，禅位        f = s; // 下一代的父亲        s = f * 2 + 1; // 下一代的儿子    &#125;    arr[f] = cur;&#125;void heapSort(vector&lt;int&gt;&amp; arr) &#123;    int n = arr.size();    // 数组形成堆    for (int p = (n - 2) / 2; p &gt;= 0; --p)        downMethod(arr, p, n);    // 堆首尾交换进行排序    for (int p = n-1; p &gt; 0; --p) &#123;        swap(arr[0], arr[p]);        downMethod(arr, 0, p);    &#125;&#125;

5.2 C#实现（借助现有堆）5.2.1 官方库（会有额外存储开销）// 45ms for 10w elements(0~10w random)public static void HeapSort&lt;T&gt;(IList&lt;T&gt; arr) where T : IComparable&lt;T&gt;&#123;    var pq = new PriorityQueue&lt;T, T&gt;(arr.Select(e =&gt; (e, e)));    int index = 0;    while (pq.Count &gt; 0)    &#123;        var max = pq.Dequeue();        arr[index++] = max;    &#125;&#125;
5.2.2 自己实现的堆（直接原地建堆）// 39ms for 10w elements(0~10w random)public static void HeapSort&lt;T&gt;(IList&lt;T&gt; arr) where T : IComparable&lt;T&gt;&#123;    var pq = new MyPriorityQueue&lt;T&gt;(arr);    var count = arr.Count;    for (int i = 0; i &lt; count - 1; ++i)    &#123;        var max = pq.Pop();        // 此时count - 1 - i及后面的元素已经不在堆里！        // 因此可以放心改变        arr[count - 1 - i] = max;    &#125;&#125;
5.2.3 通过下滤操作实现（原地建堆+原地下滤）下滤操作用于排序时，一定要考虑到当前数组的实际大小
// 29ms for 10w elements(0~10w random)public static void PriorityQueueDown&lt;T&gt;(IList&lt;T&gt; arr, int parent, int count) where T : IComparable&lt;T&gt;&#123;    var temp = arr[parent];    for (int child = (parent &lt;&lt; 1) + 1; child &lt; count; child = (parent &lt;&lt; 1) + 1)    &#123;        if (child + 1 &lt; count &amp;&amp; arr[child + 1].CompareTo(arr[child]) &gt; 0)            ++child;        if (arr[child].CompareTo(temp) &gt; 0)            arr[parent] = arr[child];        else            break;        parent = child;    &#125;    arr[parent] = temp;&#125;public static void HeapSort&lt;T&gt;(IList&lt;T&gt; arr) where T : IComparable&lt;T&gt;&#123;    int count = arr.Count;    for (int subRoot = (arr.Count - 2) &gt;&gt; 1; subRoot &gt;= 0; --subRoot)        PriorityQueueDown(arr, subRoot, count);    for (int left = arr.Count - 1; left &gt; 0; --left)    &#123;        Swap(arr, 0, left);        PriorityQueueDown(arr, 0, left);    &#125;&#125;
6. 归并排序
时间复杂度：$O(NlogN)$
空间复杂度：$O(N)$
稳定

6.1 递归版本// [l, m] [m+1, r]void mergeTwoArray(vector&lt;int&gt;&amp; arr, vector&lt;int&gt;&amp; trr, int l, int m, int r) &#123;    int i = l, j = m + 1, k = l;    while (i &lt;= m || j &lt;= r) &#123; // k &lt;= r 一样        int a = i &lt;= m ? arr[i] : INT_MAX;        int b = j &lt;= r ? arr[j] : INT_MAX;        if (a &lt; b) ++i; // 每次i和j只能有一个增加        else ++j;        trr[k++] = a &lt; b ? a : b;    &#125;    while (l &lt;= r) &#123; // 拷贝回去        arr[l] = trr[l];        ++l;    &#125;&#125;void mergeRecursion(vector&lt;int&gt;&amp; arr, vector&lt;int&gt;&amp; trr, int l, int r) &#123;    if (l == r) return;    int m = l + ((r - l) &gt;&gt; 1);    mergeRecursion(arr, trr, l, m);    mergeRecursion(arr, trr, m + 1, r);    mergeTwoArray(arr, trr, l, m, r);&#125;void mergeSort(vector&lt;int&gt;&amp; arr) &#123;    int n = arr.size();    vector&lt;int&gt; trr(arr); // 避免频繁创建子数组    mergeRecursion(arr, trr, 0, n - 1);&#125;

6.2 非递归版本// [l, m] [m+1, r]void mergeTwoArray(vector&lt;int&gt;&amp; arr, vector&lt;int&gt;&amp; trr, int l, int m, int r) &#123;    int i = l, j = m + 1, k = l;    while (i &lt;= m || j &lt;= r) &#123; // k &lt;= r 一样        int a = i &lt;= m ? arr[i] : INT_MAX;        int b = j &lt;= r ? arr[j] : INT_MAX;        if (a &lt; b) ++i; // 每次i和j只能有一个增加        else ++j;        trr[k++] = a &lt; b ? a : b;    &#125;    // 不用拷贝回去...&#125;void mergeSort(vector&lt;int&gt;&amp; arr) &#123;    int n = arr.size();    int range = 1; // 半径    vector&lt;int&gt; trr(arr); // 避免频繁创建子数组    while (range &lt; n) &#123;        for (int i = 0; i &lt; n; i += range*2) &#123; // arr -&gt; trr            int m = i + range - 1;            if (m &gt;= n - 1) m = n - 1; // 不能break            int r = i + range * 2 - 1;            if (r &gt;= n - 1) r = n - 1;            mergeTwoArray(arr, trr, i, m, r); // arr-&gt;trr        &#125;        range &lt;&lt;= 1;        for (int i = 0; i &lt; n; i += range*2) &#123; // trr -&gt; arr            int m = i + range - 1;            if (m &gt;= n - 1) m = n - 1; // 不能break            int r = i + range * 2 - 1;            if (r &gt;= n - 1) r = n - 1;            mergeTwoArray(trr, arr, i, m, r); // trr-&gt;arr        &#125;        range &lt;&lt;= 1;    &#125;&#125;

6.3 C#实现// 28ms for 10w elements(0~10w random)public static void MergeSort&lt;T&gt;(IList&lt;T&gt; arr) where T : IComparable&lt;T&gt;&#123;    List&lt;T&gt; tempList = new(arr);    //DoMergeSortRecursive(arr, tempList, 0, arr.Count - 1);    DoMergeSortIterative(arr, tempList);&#125;private static void DoMergeSortRecursive&lt;T&gt;(IList&lt;T&gt; arr, IList&lt;T&gt; tempList, int l, int r) where T : IComparable&lt;T&gt;&#123;    if (l &gt;= r)        return;    int m = (l + r) &gt;&gt; 1;    DoMergeSortRecursive(arr, tempList, l, m);    DoMergeSortRecursive(arr, tempList, m + 1, r);    Merge(arr, tempList, l, m + 1, r);    for (int i = l; i &lt;= r; i++)        arr[i] = tempList[i];&#125;// 公用mergeprivate static void Merge&lt;T&gt;(IList&lt;T&gt; arr, IList&lt;T&gt; tempList, int lStart, int rStart, int rEnd) where T : IComparable&lt;T&gt;&#123;    var lEnd = rStart - 1;    var indexT = lStart;    while (lStart &lt;= lEnd &amp;&amp; rStart &lt;= rEnd)    &#123;        if (arr[lStart].CompareTo(arr[rStart]) &lt;= 0) tempList[indexT++] = arr[lStart++];        else tempList[indexT++] = arr[rStart++];    &#125;    while (lStart &lt;= lEnd) tempList[indexT++] = arr[lStart++];    while (rStart &lt;= rEnd) tempList[indexT++] = arr[rStart++];&#125;// 这一步最是精髓private static void DoMergeSortIterative&lt;T&gt;(IList&lt;T&gt; arr, IList&lt;T&gt; tempList) where T : IComparable&lt;T&gt;&#123;    int mergeSize = 1;    while (mergeSize &lt; arr.Count)    &#123;        DoMergeOnce(arr, tempList, mergeSize);        mergeSize &lt;&lt;= 1;        DoMergeOnce(tempList, arr, mergeSize);        mergeSize &lt;&lt;= 1;    &#125;&#125;private static void DoMergeOnce&lt;T&gt;(IList&lt;T&gt; arr, IList&lt;T&gt; tempList, int mergeSize) where T : IComparable&lt;T&gt;&#123;    int lStart = 0;    for (; lStart + mergeSize &lt; arr.Count; lStart += mergeSize &lt;&lt; 1)    &#123;        int rStart = lStart + mergeSize;        int rEnd = Math.Min(rStart + mergeSize - 1, arr.Count - 1);        Merge(arr, tempList, lStart, rStart, rEnd);    &#125;    if (lStart &lt; arr.Count)        Merge(arr, tempList, lStart, arr.Count, arr.Count - 1);&#125;

6.4 归并排序思考归并时，一定要对等长的数据进行归并吗，比如[1,2,3,6,10]和[4,5,7,9,12,14,17]。第一个序列的最后一个位（最大值）在第二个序列里应该排序到12前面；第二个序列的第一位（最小值）在第一个序列里应该排序到3后面。所以实际归并的序列应该是...[6,10]和[4,5,7,9]...，那针对这次归并，我其实只需要大小为2的临时数组寄放最短的序列，然后归并到原数组。当然，普通的归并排序，是事先创建好的一整块同大小的内存，以防止频繁重复的申请内存，所以实际的内存看来是省不下来的，但是数据搬运和比较的次数是有望减少的。
7. 快速排序
时间复杂度：$O(NlogN)$
空间复杂度：栈上$O(logN)$
不稳定
注意1：遇到l和r指向相等时，需要交换，不然遇到全1的数组，退化为n^2
注意2：快排在数据范围较小时（r-l&lt;threshold）直接使用插入排序可有效优化速度

7.1 实现1（朴素版）void quickRecursion(vector&lt;int&gt;&amp; arr, int l, int r) &#123;    if (l &gt;= r) return;    int oldl = l, oldr = r;    // 选 [枢纽]    int pivot = arr[l];    // 排序    ++r;    while (l &lt; r) &#123;        while (l &lt; r &amp;&amp; arr[--r] &gt; pivot); // 右侧先动是安全的        while (l &lt; r &amp;&amp; arr[++l] &lt; pivot); // 左侧后动        if (l &lt; r) swap(arr[l], arr[r]);    &#125;    swap(arr[oldl], arr[l]);    quickRecursion(arr, oldl, r - 1);    quickRecursion(arr, r + 1, oldr);&#125;void quickSort(vector&lt;int&gt;&amp; arr) &#123;    int n = arr.size();    quickRecursion(arr, 0, n - 1);&#125;

7.2 实现2（改进朴素版）int pivot = arr[l];// 改为int randomPos = l + rand()%(r-l+1);swap(arr[l], arr[randomPos]);int pivot = arr[l];

7.3 实现3（中间值枢纽）// 三数选中间数并将最小值放在l，最大值放在r，中间值(pivot)放在l+1// 陈姥姥代码里是放在r-1的，这样肯定正确因为m肯定&lt;r// 我为了兼容朴素版的大部分代码，选择放在l+1，这样由于m可能等于l，所以需要多一次特殊点判断int median3(vector&lt;int&gt;&amp; arr, int l, int r) &#123;    int m = l + ((r - l) &gt;&gt; 1);    if (arr[l] &gt; arr[m])        swap(arr[l], arr[m]);    if (arr[l] &gt; arr[r])        swap(arr[l], arr[r]);    if (arr[m] &gt; arr[r])        swap(arr[m], arr[r]);    if (l == m) return arr[l]; // 特殊点    swap(arr[m], arr[l + 1]);    return arr[l + 1];&#125;void quickRecursion(vector&lt;int&gt;&amp; arr, int l, int r) &#123;    if (l &gt;= r) return;    int oldl = l, oldr = r;    // 选 [枢纽]    int pivot = median3(arr, l, r);    // 排序    ++l; // 注意：两端收缩了一位    while (l &lt; r) &#123;        while (l &lt; r &amp;&amp; arr[--r] &gt; pivot); // 右侧先动是安全的        while (l &lt; r &amp;&amp; arr[++l] &lt; pivot); // 左侧后动        if (l &lt; r) swap(arr[l], arr[r]);    &#125;    swap(arr[oldl + 1], arr[l]); // 注意：pivot枢纽放在了l+1位置    quickRecursion(arr, oldl, r - 1);    quickRecursion(arr, r + 1, oldr);&#125;void quickSort(vector&lt;int&gt;&amp; arr) &#123;    int n = arr.size();    quickRecursion(arr, 0, n - 1);&#125;

7.4 实现4（有限制）虽然代码看起来很简洁，但是有如下问题：

极端情况会退化为n^2算法
正因如此，在我的实验中，对3w个分布0~99的数字排序，会栈溢出（异常结束，main函数return 非0）。其实前面的方法里，移动i和j时如果&gt;改为&gt;=、&lt;改为&lt;=也会出现这种问题哦。因此在数据分布较窄时，这种方法无疑是低效的
快速排序中，任何通过单边移动的方法，在面对窄数据时，都会向$O(N^2)$退化。而即便是两边从中间移动，如果比较相等时不停下交换，也会在面对窄数据时，退化成$O(N^2)$

void quickRecursion(vector&lt;int&gt;&amp; arr, int l, int r) &#123;    if (l &gt;= r) return;    // 选 [枢纽] 可改进随机化但效果还是差    int pivot = arr[l];    // 排序    int j = l;    for (int i = l + 1; i &lt;= r; ++i) &#123;        if (arr[i] &lt; pivot) &#123;            ++j;            swap(arr[i], arr[j]);        &#125;    &#125;    swap(arr[j], arr[l]);    quickRecursion(arr, l, j - 1);    quickRecursion(arr, j + 1, r);&#125;void quickSort(vector&lt;int&gt;&amp; arr) &#123;    int n = arr.size();    quickRecursion(arr, 0, n - 1);&#125;

7.5 C#实现// 快速排序public static void QuickSort&lt;T&gt;(IList&lt;T&gt; arr) where T : IComparable&lt;T&gt;&#123;    DoQuickSort_1(arr, 0, arr.Count - 1);&#125;// 23ms for 10w elements(0~10w random)// 21ms for 10w elements(0~100 random)// 快速排序（自己随便实现的）private static void DoQuickSort_1&lt;T&gt;(IList&lt;T&gt; arr, int l, int r) where T : IComparable&lt;T&gt;&#123;    if (r - l &lt; 16)    &#123;        InsertSort(arr, l, r);        return;    &#125;    var pivot = arr[l];    int indexL = l + 1, indexR = r;    while (indexL &lt; indexR)    &#123;        bool moved = false;        while (indexL &lt; indexR &amp;&amp; arr[indexL].CompareTo(pivot) &lt; 0)        &#123;            ++indexL;            moved = true;        &#125;        while (indexL &lt; indexR &amp;&amp; arr[indexR].CompareTo(pivot) &gt; 0)        &#123;            --indexR;            moved = true;        &#125;        Swap(arr, indexL, indexR);        if (!moved)        &#123;            ++indexL;            --indexR;        &#125;    &#125;    if (arr[indexL].CompareTo(pivot) &gt;= 0)        --indexL;    Swap(arr, l, indexL);    DoQuickSort_1(arr, l, indexL - 1);    DoQuickSort_1(arr, indexL + 1, r);&#125;// 18ms for 10w elements(0~10w random)// 15ms for 10w elements(0~100 random)// 快速排序（基础版）private static void DoQuickSort_Scratch&lt;T&gt;(IList&lt;T&gt; arr, int l, int r) where T : IComparable&lt;T&gt;&#123;    if (r - l &lt; 16)    &#123;        InsertSort(arr, l, r);        return;    &#125;    var pivot = arr[l];    int indexL = l, indexR = r + 1;    while (true)    &#123;        // 因为左侧有哨兵，必须右侧先移动        while (arr[--indexR].CompareTo(pivot) &gt; 0) ; // 左侧枢纽作为哨兵，所以这里不需要判断指针大小        while (indexL &lt; indexR &amp;&amp; arr[++indexL].CompareTo(pivot) &lt; 0) ; // 右侧由于没有哨兵，所以需要判断指针大小        if (indexL &lt; indexR)            Swap(arr, indexL, indexR);        else            break;    &#125;    Swap(arr, l, indexL);    DoQuickSort_Scratch(arr, l, indexL - 1);    DoQuickSort_Scratch(arr, indexL + 1, r);&#125;// 17ms for 10w elements(0~10w random)// 14ms for 10w elements(0~100 random)// 枢纽三选一中位数private static void DoQuickSort_Three&lt;T&gt;(IList&lt;T&gt; arr, int l, int r) where T : IComparable&lt;T&gt;&#123;    // 必须进行截断，否则只有两个元素，下面的代码indexR必会越界    if (r - l &lt; 16)    &#123;        InsertSort(arr, l, r);        return;    &#125;    int m = (l + r) &gt;&gt; 1;    if (arr[l].CompareTo(arr[m]) &gt; 0)        Swap(arr, l, m);    if (arr[m].CompareTo(arr[r]) &gt; 0)        Swap(arr, m, r);    if (arr[l].CompareTo(arr[m]) &gt; 0)        Swap(arr, l, m);    Swap(arr, m, r - 1); // 锚点暂存右边第二位，这样即使只有两个元素，也是完全正确的    var pivot = arr[r - 1];    int indexL = l, indexR = r - 1;    while (true)    &#123;        // 下面的顺序无所谓        while (arr[++indexL].CompareTo(pivot) &lt; 0) ; // 左右侧都有哨兵，可以消去判断指针大小的语句        while (arr[--indexR].CompareTo(pivot) &gt; 0) ; // 左右侧都有哨兵，可以消去判断指针大小的语句        if (indexL &lt; indexR)            Swap(arr, indexL, indexR);        else            break;    &#125;    // 需要将数换回来，由于锚点在右侧，所以需要一个大于等于锚点的值，indexL满足；indexR是小于等于锚点的值，不满足    Swap(arr, indexL, r - 1);    DoQuickSort_Three(arr, l, indexL - 1);    DoQuickSort_Three(arr, indexL + 1, r);&#125;

三、特殊排序8. 计数排序（累加和的策略很巧妙）
时间复杂度：$O(B+N)$，B是数据范围一般较小，可认为是$O(N)$
空间复杂度：栈上$O(B+N)$ -&gt; $O(N)$
稳定（实现的不好则不稳定，比如从前往后填）

void countingSort(vector&lt;int&gt;&amp; arr) &#123;    int n = arr.size();    int maxV = INT_MIN;    for (auto&amp; e : arr) maxV = maxV &gt; e ? maxV : e;    vector&lt;int&gt; counting(maxV + 1); // 计数数组    vector&lt;int&gt; trr(arr); // 留作中转拷贝    for (auto&amp; e : arr) ++counting[e]; // 计数    for (int i = 1; i &lt; counting.size(); ++i) // 累加计数        counting[i] = counting[i - 1] + counting[i];    for (int i = n - 1; i &gt;= 0; --i) &#123; // 从后向前填：稳定的排序        int pos = --counting[arr[i]];        trr[pos] = arr[i];    &#125;    for (int i = 0; i &lt; n; ++i) // 拷回去        arr[i] = trr[i];&#125;

9. 基数排序
时间复杂度：$O(Rs * N)$，Rs是数据最大值的位数一般较小，可认为是$O(N)$
空间复杂度：栈上$O(10 + N)$ -&gt; $O(N)$
稳定（对MSD来说实现的不好则不稳定，比如从前往后填）
经常利用计数排序实现

9.1 LSD基数排序
最低位优先(Least Significant Digit first, LSD)，先排低位；再排高位
由于每一位介于0~9，所以对每一个基位排序时都可看做是分为10个桶的桶排序

// 获得一个int的某一位的数字// 例如13247 r=0 -&gt; 7 | r=1 -&gt; 4 | r=2 -&gt; 2 | r=3 -&gt; 3 | r=4 -&gt; 1 | r = 5 -&gt; 0 int getRadix(int num, int r) &#123;    static int radices[] = &#123; 1, 10, 100, 1000, 10000, 100000, 1000000, 10000000, 100000000, 1000000000 &#125;;    num %= radices[r + 1];    return num / radices[r];&#125;void radixSortLSD(vector&lt;int&gt;&amp; arr) &#123;    int n = arr.size();    int maxV = INT_MIN;    for (auto&amp; e : arr) maxV = maxV &gt; e ? maxV : e;    int radixNum = 0;    while (maxV) &#123;        ++radixNum;        maxV /= 10;    &#125;    vector&lt;int&gt; trr(arr); // 留作中转拷贝    for (int r = 0; r &lt; radixNum; ++r) &#123;        vector&lt;int&gt; counting(10); // 计数数组        for (auto&amp; e : arr) ++counting[getRadix(e, r)]; // 计数        for (int i = 1; i &lt; counting.size(); ++i) // 累加计数            counting[i] = counting[i - 1] + counting[i];        for (int i = n - 1; i &gt;= 0; --i) &#123;            int pos = --counting[getRadix(arr[i], r)];            trr[pos] = arr[i];        &#125;        for (int i = 0; i &lt; n; ++i) // 拷回去            arr[i] = trr[i];    &#125;&#125;
// 17ms for 10w elements(0~10w random)// 8ms for 10w elements(0~100 random)// 基数排序（十六进制）public static void RadixSort(IList&lt;int&gt; arr)&#123;    List&lt;List&lt;int&gt;&gt; buckets = Enumerable.Range(0, 16).Select(_ =&gt; new List&lt;int&gt;()).ToList();    uint mask = 0x0f;    int shiftCount = 0;    while (mask &gt; 0)    &#123;        foreach (var item in arr)        &#123;            var index = (int)((item &amp; mask) &gt;&gt; shiftCount);            buckets[index].Add(item);        &#125;        if (buckets[0].Count == arr.Count)            break;        var iterator = buckets.SelectMany(e =&gt; e);        var i = 0;        foreach (var item in iterator)            arr[i++] = item;        foreach (var bucket in buckets)            bucket.Clear();        mask &lt;&lt;= 4;        shiftCount += 4;    &#125;&#125;

// 12ms for 10w elements(0~10w random)// 6ms for 10w elements(0~100 random)// 基数排序（十六进制）（计数优化）public static void RadixCountSort(IList&lt;int&gt; arr)&#123;    List&lt;int&gt; tempList = new(arr);    uint mask = 0xf;    int shiftCount = 0;    while (mask &gt; 0)    &#123;        List&lt;int&gt; counting = Enumerable.Repeat(0, 16).ToList();        foreach (var item in arr)        &#123;            var index = (int)((item &amp; mask) &gt;&gt; shiftCount);            ++counting[index];        &#125;        if (counting[0] == arr.Count)            break;        for (int i = 1; i &lt; counting.Count; ++i)            counting[i] += counting[i - 1];        // 错误！因为arr继承自上一次低基排序的顺序        // counting的计数又是默认从后往前        // 因此，对本次基数的排序必须也是从后往前，这样才能保持低基的顺序不会被打乱        // 它不是稳定不稳定的问题，而是排序会完全错误        //foreach (var item in arr)        //&#123;        //    var index = (int)((item &amp; mask) &gt;&gt; shiftCount);        //    tempList[--counting[index]] = item;        //&#125;        // 必须是从后往前        for (int i = arr.Count - 1; i &gt;= 0; --i)        &#123;            var index = (int)((arr[i] &amp; mask) &gt;&gt; shiftCount);            tempList[--counting[index]] = arr[i];        &#125;        for (int i = 0; i &lt; arr.Count; ++i)            arr[i] = tempList[i];        shiftCount += 4;        mask &lt;&lt;= 4;    &#125;&#125;
9.2 MSD基数排序
最高位优先(Most Significant Digit first, MSD)，先排高位；再排低位
MSD一般采用递归写法：按高位分组，形成连续区段，然后在区段内递归处理低一位
与之前的计数策略不同，这里进行写入临时数组时，如果不采用从后往前的策略，虽然不至于排序错误，但是会使得排序不稳定

// 13ms for 10w elements(0~10w random)// 6ms for 10w elements(0~100 random)public static void MSD(IList&lt;int&gt; arr)&#123;    List&lt;int&gt; trr = new(arr);    var maxItem = int.MinValue;    foreach (var item in trr)        maxItem = Math.Max(maxItem, item);    int shiftCount = 0;    uint mask = 0x0000000f;    while (maxItem &gt; mask)    &#123;        shiftCount += 4;        maxItem &gt;&gt;= 4;    &#125;    mask &lt;&lt;= shiftCount; // 得到最大的遮罩    DoMSD(arr, trr, 0, arr.Count - 1, mask);&#125;// 获得遮罩的额外位移次数private static int ShiftCount(uint mask)&#123;    var single = mask &amp; -mask; // 可以快速获取二进制最低位的1    int shiftCount = 0;    while (single &gt; 0)    &#123;        ++shiftCount;        single &gt;&gt;= 1;    &#125;    return shiftCount - 1;&#125;private static void DoMSD(IList&lt;int&gt; arr, IList&lt;int&gt; trr, int l, int r, uint mask)&#123;    if (l &gt;= r || mask == 0)        return;    var counting = Enumerable.Repeat(0, 16).ToList();    var shiftCount = ShiftCount(mask);    // l~r计数    for (int i = l; i &lt;= r; ++i)    &#123;        var index = (int)((arr[i] &amp; mask) &gt;&gt; shiftCount);        ++counting[index];    &#125;    for (int i = 1; i &lt; counting.Count; ++i)        counting[i] += counting[i - 1];    /*    * 从前往后，虽然不至于像LSD那样直接排序错误，但是会导致排序不稳定。之所以不会排序错误，    * 是因为MSD是先序遍历的递归，每一层处理时只负责分组，不会包含次级排序的信息    */    //for (int i = l; i &lt;= r; ++i)    //&#123;    //    var index = (int)((arr[i] &amp; mask) &gt;&gt; shiftCount);    //    trr[--counting[index] + l] = arr[i]; // + l的偏移别忘了    //&#125;    // 还是得从后往前进行    for (int i = r; i &gt;= l; --i)    &#123;        var index = (int)((arr[i] &amp; mask) &gt;&gt; shiftCount);        trr[--counting[index] + l] = arr[i]; // + l的偏移别忘了    &#125;    for (int i = l; i &lt;= r; ++i)        arr[i] = trr[i];    for (int i = 0; i &lt; 16; ++i)    &#123;        if (i &lt; 15)            DoMSD(arr, trr, l + counting[i], l + counting[i + 1] - 1, mask &gt;&gt; 4);        else            DoMSD(arr, trr, l + counting[i], r, mask &gt;&gt; 4);    &#125;&#125;

10. 桶排序（更像是一种思路，而非特定的算法）
桶排序的时间复杂度和空间复杂度以及是不是稳定都看你采取的子排序算法
桶排序一般用于数据分布均匀的
桶排序用于遏制N^2、NlogN等复杂度的算法因数据量太大而带来的速度问题

void insertSort(vector&lt;int&gt;&amp; arr) &#123;    int n = arr.size();    for (int i = 1; i &lt; n; ++i) &#123;        int cur = arr[i];        int j = i - 1;        for (; j &gt;= 0 &amp;&amp; arr[j] &gt; cur; --j)            arr[j + 1] = arr[j];        arr[j + 1] = cur;    &#125;&#125;void bucketSort(vector&lt;int&gt;&amp; arr) &#123;    int n = arr.size();    int maxV = INT_MIN;    for (auto&amp; e : arr) maxV = maxV &gt; e ? maxV : e;    ++maxV;    int bckNum = 10; // 分十个桶    vector&lt;vector&lt;int&gt;&gt; buckets(bckNum, vector&lt;int&gt;());    for (auto&amp; e : arr) &#123;        int pos = e * 10 / maxV;        buckets[pos].push_back(e); // 放进桶里    &#125;    for (auto&amp; b : buckets) &#123; // 随意选取排序算法        insertSort(b);    &#125;    int k = 0;    for (int i = 0; i &lt; buckets.size(); ++i)        for (int j = 0; j &lt; buckets[i].size(); ++j)            arr[k++] = buckets[i][j]; // 从桶里面拿出来&#125;

