一. 子集问题78 子集划分1.1 子集扩张class Solution &#123;public:    vector&lt;vector&lt;int&gt;&gt; subsets(vector&lt;int&gt;&amp; nums) &#123;        if(nums.empty())            return vector&lt;vector&lt;int&gt;&gt;(1, vector&lt;int&gt;());        int last = nums.back(); nums.pop_back();        vector&lt;vector&lt;int&gt;&gt; sub = subsets(nums);        int sz = sub.size();        for(int i=0; i&lt;sz; ++i)&#123;            vector&lt;int&gt; tmp = sub[i];            tmp.push_back(last);            sub.push_back(tmp);        &#125;        return sub;    &#125;&#125;;

1.2 回溯1class Solution &#123;public:    vector&lt;vector&lt;int&gt;&gt; ret;    vector&lt;int&gt; cur;    void traceback(vector&lt;int&gt;&amp; nums, int pos)&#123;        if(pos == nums.size())&#123;            ret.push_back(cur);            return;        &#125;        // 选        cur.push_back(nums[pos]);        traceback(nums, pos+1);        cur.pop_back();                // 不选        traceback(nums, pos+1);    &#125;        vector&lt;vector&lt;int&gt;&gt; subsets(vector&lt;int&gt;&amp; nums) &#123;        traceback(nums, 0);        return ret;    &#125;&#125;;

1.3 回溯2(★)class Solution &#123;public:    vector&lt;vector&lt;int&gt;&gt; ret;    vector&lt;int&gt; cur;    void traceback(vector&lt;int&gt;&amp; nums, int pos)&#123;        ret.push_back(cur);        for(int i=pos; i&lt;nums.size(); ++i)&#123;            cur.push_back(nums[i]);            traceback(nums, i+1);            cur.pop_back();        &#125;    &#125;        vector&lt;vector&lt;int&gt;&gt; subsets(vector&lt;int&gt;&amp; nums) &#123;        traceback(nums, 0);        return ret;    &#125;&#125;;

90 子集划分Ⅱ
两条值相同的相邻树枝会产生重复，如果一个节点有多条值相同的树枝相邻，则只遍历第一条，剩下的都剪掉，不要去遍历（不能让队员越权）
“使用过”在这个树形结构上是有两个维度的，一个维度是同一树枝上使用过，一个维度是同一树层上使用过。 我们要去重的是同一树层上的“使用过”，同一树枝上的都是一个组合里的元素，不用去重。（注意：这里的同一树层指的是由同一个父节点引出的子节点，叔伯的子节点可以用相同下一个值，比如下图[1]接2和[2]接2，都可以用2；但是[1]接2就不能接2’了！）


2.1 回溯1class Solution &#123;public:    vector&lt;int&gt; cur;    vector&lt;vector&lt;int&gt;&gt; ret;    void traceback(bool choosePre, int pos, vector&lt;int&gt; &amp;nums) &#123;        if (pos == nums.size()) &#123;            ret.push_back(t);            return;        &#125;        // 不选        traceback(false, cur + 1, nums);                // 要在 [选] 之前执行，要在 [不选] 之后执行        if (!choosePre &amp;&amp; pos &gt; 0 &amp;&amp; nums[pos - 1] == nums[pos]) return;                // 选        cur.push_back(nums[pos]);        traceback(true, pos + 1, nums);        cur.pop_back();    &#125;    vector&lt;vector&lt;int&gt;&gt; subsetsWithDup(vector&lt;int&gt; &amp;nums) &#123;        sort(nums.begin(), nums.end());        traceback(false, 0, nums);        return ret;    &#125;&#125;;

2.2 回溯2(★)class Solution &#123;public:    vector&lt;vector&lt;int&gt;&gt; ret;    vector&lt;int&gt; cur;    void backtrack(vector&lt;int&gt;&amp; nums, int pos)&#123;        ret.push_back(cur);        for(int i=pos; i&lt;nums.size(); ++i)&#123;            // i从pos开始，天然可以判定同一父节点的子节点们不会重复            // 即只让重复段的第一个节点的树向下生长            // 如果i从0开始，无法确定pos-1位置是否使用过，需要            // 借助一个used数组            if(i &gt; pos &amp;&amp; nums[i] == nums[i-1]) continue;            cur.push_back(nums[i]);            backtrack(nums, i+1);            cur.pop_back();        &#125;    &#125;        vector&lt;vector&lt;int&gt;&gt; subsetsWithDup(vector&lt;int&gt;&amp; nums) &#123;        sort(nums.begin(), nums.end()); // 要排序        backtrack(nums, 0);        return ret;    &#125;&#125;;

2.3 回溯2（易读版利用used判断树层重复）也可用used数组来简化理解，nums[i]与nums[i-1]相等，且nums[i-1]没有使用的情况下，表明重复了，因为只有在nums[i-1]用过之后才会不用，而nums[i-1]之前用过，其后的子树是已经加入到结果了，即可跳过当前点
class Solution &#123;private:    vector&lt;vector&lt;int&gt;&gt; ret;    vector&lt;int&gt; cur;    void backtracking(vector&lt;int&gt;&amp; nums, int pos, vector&lt;bool&gt;&amp; used) &#123;        ret.push_back(cur);        for (int i = pos; i &lt; nums.size(); i++) &#123;            // used[i-1] == true，说明同一树支nums[i-1]使用过            // used[i-1] == false，说明同一树层nums[i-1]使用过            // 而我们要对同一树层使用过的元素进行跳过            if (i &gt; 0 &amp;&amp; nums[i] == nums[i - 1] &amp;&amp; !used[i-1]) continue;            used[i] = true;            cur.push_back(nums[i]);            backtracking(nums, i + 1, used);            cur.pop_back();            used[i] = false;        &#125;    &#125;public:    vector&lt;vector&lt;int&gt;&gt; subsetsWithDup(vector&lt;int&gt;&amp; nums) &#123;        vector&lt;bool&gt; used(nums.size(), false);        sort(nums.begin(), nums.end()); // 去重需要排序        backtracking(nums, 0, used);        return ret;    &#125;&#125;;

二. 组合问题39 组合总数1.1 回溯nums中的每个数字可以多次使用
class Solution &#123;public:    vector&lt;vector&lt;int&gt;&gt; ret;    vector&lt;int&gt; cur;    void backtrack(vector&lt;int&gt;&amp; nums, int pos, int target)&#123;        if(target &lt;= 0)&#123;            if(target == 0) ret.push_back(cur);            return;        &#125;        for(int i=pos; i&lt;nums.size(); ++i)&#123;            cur.push_back(nums[i]);            backtrack(nums, i, target-nums[i]); // 依旧传入i            cur.pop_back();        &#125;    &#125;    vector&lt;vector&lt;int&gt;&gt; combinationSum(vector&lt;int&gt;&amp; nums, int target) &#123;        backtrack(nums, 0, target);        return ret;    &#125;&#125;;

2. 40 组合总数Ⅱnums中的每个数字在每个组合中只能使用一次 &amp;&amp; 解集不能包含重复的组合。
说这是一个组合问题，其实换个问法就变成子集问题了：请你计算 candidates 中所有和为 target 的子集。
2.1 回溯1class Solution &#123;public:    vector&lt;vector&lt;int&gt;&gt; ret;    vector&lt;int&gt; cur;    void backtrack(vector&lt;int&gt;&amp; nums, int pos, int target, bool preUsed)&#123;        if(target &lt; 0) return;        if(target == 0)&#123;            ret.push_back(cur);            return;        &#125;        if(pos &gt;= nums.size()) return; // 不能放前面        if(nums[pos] &gt; target) return; // 剪枝：当前和后面的不可能会选                // 不选        backtrack(nums, pos+1, target, false);                if(pos&gt;0 &amp;&amp; nums[pos-1] == nums[pos] &amp;&amp; !preUsed) return;                // 选        cur.push_back(nums[pos]);        backtrack(nums, pos+1, target - nums[pos], true);        cur.pop_back();    &#125;    vector&lt;vector&lt;int&gt;&gt; combinationSum2(vector&lt;int&gt;&amp; nums, int target) &#123;        sort(nums.begin(), nums.end());        backtrack(nums, 0, target, false);        return ret;    &#125;&#125;;

2.2 回溯2(★)class Solution &#123;public:    vector&lt;vector&lt;int&gt;&gt; ret;    vector&lt;int&gt; cur;    void backtrack(vector&lt;int&gt;&amp; nums, int pos, int target)&#123;        if(target == 0)&#123;            ret.push_back(cur);            return;        &#125;        for(int i=pos; i&lt;nums.size(); ++i)&#123;            if(i&gt;pos &amp;&amp; nums[i-1] == nums[i]) continue; // 值相同的树枝，只遍历第一条，防止重复            if(target &lt; nums[i]) return; // 剪枝：当前和后面的不可能会选            cur.push_back(nums[i]);            backtrack(nums, i+1, target-nums[i]);            cur.pop_back();        &#125;    &#125;    vector&lt;vector&lt;int&gt;&gt; combinationSum2(vector&lt;int&gt;&amp; nums, int target) &#123;        sort(nums.begin(), nums.end());        backtrack(nums, 0, target);        return ret;    &#125;&#125;;


三. 排列问题1. 46 全排列不含重复数字的数组：nums，经典回溯
class Solution &#123;public:    vector&lt;vector&lt;int&gt;&gt; ret;    vector&lt;int&gt; cur;    void backtrack(vector&lt;int&gt;&amp; nums, vector&lt;bool&gt;&amp; used)&#123;        if(cur.size() == nums.size())&#123;            ret.push_back(cur);            return;        &#125;        for(int i=0; i&lt;nums.size(); ++i)&#123;            if(used[i]) continue;            used[i] = true;            cur.push_back(nums[i]);            backtrack(nums, used);            cur.pop_back();            used[i] = false;        &#125;    &#125;    vector&lt;vector&lt;int&gt;&gt; permute(vector&lt;int&gt;&amp; nums) &#123;        vector&lt;bool&gt; used(nums.size(), false);        backtrack(nums, used);        return ret;    &#125;&#125;;

2. 47 全排列Ⅱ含有重复数字的数组：nums
2.1 哈希（有意思）class Solution &#123;public:    vector&lt;vector&lt;int&gt;&gt; res;        void traceback(map&lt;int, int&gt;&amp; hash, vector&lt;int&gt;&amp; cur, int n)&#123;        if(cur.size() == n)&#123;            res.push_back(cur);            return;        &#125;        for(map&lt;int, int&gt;::iterator itr=hash.begin(); itr!=hash.end(); ++itr)&#123;            if(itr-&gt;second)&#123;                --itr-&gt;second;                cur.push_back(itr-&gt;first);                traceback(hash, cur, n);                cur.pop_back();                ++itr-&gt;second;            &#125;        &#125;    &#125;        vector&lt;vector&lt;int&gt;&gt; permuteUnique(vector&lt;int&gt;&amp; nums) &#123;        map&lt;int, int&gt; hash;        vector&lt;int&gt; cur;        for(auto e: nums) ++hash[e];        traceback(hash, cur, nums.size());        return res;    &#125;&#125;;

2.2 回溯(跟子集问题2.3很像)当出现重复元素时，比如输入 nums &#x3D; [1,2,2’,2’’]，2’ 只有在 2 已经被使用的情况下才会被选择，2’’ 只有在 2’ 已经被使用的情况下才会被选择，这就保证了相同元素在排列中的相对位置保证固定。
class Solution &#123;public:    vector&lt;vector&lt;int&gt;&gt; ret;    vector&lt;int&gt; cur;    void backtrack(vector&lt;int&gt;&amp; nums, vector&lt;bool&gt;&amp; used)&#123;        if(cur.size() == nums.size())&#123;            ret.push_back(cur);            return;        &#125;        for(int i=0; i&lt;nums.size(); ++i)&#123;            // i从0开始，固定相同的元素在排列中的相对位置            if(i&gt;0 &amp;&amp; nums[i]==nums[i-1] &amp;&amp; !used[i-1]) continue;            if(used[i]) continue;            used[i] = true;            cur.push_back(nums[i]);            backtrack(nums, used);            cur.pop_back();            used[i] = false;        &#125;    &#125;        vector&lt;vector&lt;int&gt;&gt; permuteUnique(vector&lt;int&gt;&amp; nums) &#123;        sort(nums.begin(), nums.end()); // 必须排序        vector&lt;bool&gt; used(nums.size(), false);        backtrack(nums, used);        return ret;    &#125;&#125;;

43 字符串相乘两数A位和B位，相加后位数最大为max(A, B)+1；相乘后最大位数为A+B
1.1 常规法将两个串的指针位置m和n、进位c统一放入while循环，代码就会很优美。 代码可以继续优化速度存储：addtion函数改为原地相加，但是会破坏代码的逻辑性，就不改了。
class Solution &#123;public:    string addtion(string&amp; num1, string&amp; num2)&#123;        int m = num1.size()-1, n = num2.size()-1;        int c = 0;        string ret;        while(m&gt;=0 || n&gt;=0 || c)&#123;            int a = m&gt;=0 ? num1[m]-&#x27;0&#x27; : 0; // 越界定0技巧            int b = n&gt;=0 ? num2[n]-&#x27;0&#x27; : 0; // 越界定0技巧            int s = a + b + c;            ret.push_back(&#x27;0&#x27; + s % 10);            c = s / 10;            --m, --n;        &#125;        reverse(ret.begin(), ret.end()); // 反转        return ret;    &#125;        string multiply(string num1, string num2) &#123;        if(num1==&quot;0&quot; || num2==&quot;0&quot;) return &quot;0&quot;;        string res = &quot;0&quot;;        int cnt = 0; // 记录表示每次乘完左移的0的个数        int m = num2.size()-1;        while(m &gt;= 0)&#123;            int n = num1.size()-1;            int b = num2[m] - &#x27;0&#x27;;            int c = 0;            string ret(cnt, &#x27;0&#x27;); // 初始化&quot;左移&quot;0            while(n&gt;=0 || c)&#123;                int a = n&gt;=0 ? num1[n]-&#x27;0&#x27; : 0; // 越界定0技巧                int s = a * b + c;                ret.push_back(&#x27;0&#x27; + s % 10);                c = s / 10;                --n;            &#125;            reverse(ret.begin(), ret.end()); // 反转            res = addtion(res, ret);            --m, ++cnt;        &#125;        return res;    &#125;&#125;;

1.2 优化竖式 (LC高赞)(很难想到啊)num1[i] x num2[j] 的结果为 tmp(位数为两位，”0x”,”xy”的形式)，其第一位位于 res[i+j]，第二位位于 res[i+j+1]。
class Solution &#123;public:    string multiply(string num1, string num2) &#123;        if(num1 == &quot;0&quot; || num2 == &quot;0&quot;) return &quot;0&quot;;        int m = num1.size(), n = num2.size();        vector&lt;int&gt; temp(m+n, 0); // 数组哦        for(int i=m-1; i&gt;=0; --i)&#123;            for(int j=n-1; j&gt;=0; --j)&#123;                int cur = (num1[i]-&#x27;0&#x27;) * (num2[j]-&#x27;0&#x27;) + temp[i+j+1];                temp[i+j+1] = cur % 10; // 存储计算结果低位 =                temp[i+j] += cur / 10; // 存储计算结果高位 +=            &#125;        &#125;        string ret; ret.reserve(m+n);        int i = 0;        for(; i&lt;temp.size(); ++i) // 去掉前缀0            if(temp[i] != 0) break;        for(; i&lt;temp.size(); ++i) // 放入字符串            ret.push_back(char(temp[i] + &#x27;0&#x27;));        return ret;    &#125;&#125;;

带限制的最短路
错误示例（Dijkstra）全局的dist记录着最短距离，但它并未记录是几跳获得的。例如，到达终点的前一跳，从X-&gt;dst，我的代码中只限制了到达X最多k+1跳，此时更新了dist[X]，当更新到dst时，利用的dist[X]是经过k跳的X作为跳板，则结果是经过了k+2跳，超出了限制，因此结果必然是错误的。
class Item &#123;public:    int node, skip, dis;    Item(int a, int b, int c):node(a),skip(b),dis(c)&#123;&#125;    bool operator&gt;(const Item&amp; R) const &#123;        return this-&gt;dis &gt; R.dis;    &#125;&#125;;class Solution &#123;public:    int INF = 0x3f3f3f3f;    int findCheapestPrice(int n, vector&lt;vector&lt;int&gt;&gt;&amp; flights, int src, int dst, int k) &#123;        vector&lt;vector&lt;pair&lt;int, int&gt;&gt;&gt; g(n);        for (auto&amp; e : flights) g[e[0]].push_back(&#123; e[1], e[2] &#125;);        vector&lt;int&gt; dist(n, INF);        dist[src] = 0;        priority_queue&lt;Item, vector&lt;Item&gt;, greater&lt;Item&gt;&gt; pq;        pq.emplace(src, 0, 0);        while (!pq.empty()) &#123;            auto cur = pq.top(); pq.pop();            int node = cur.node;            int dis = cur.dis;            int skip = cur.skip;            if (skip &gt; k) continue;            for (auto&amp; e : g[node]) &#123;                int w_node = e.first;                int w_weight = e.second;                if (dist[w_node] &gt; dist[node] + w_weight) &#123;                    dist[w_node] = dist[node] + w_weight;                    pq.emplace(w_node, skip + 1, dist[w_node]);                &#125;            &#125;        &#125;        return dist[dst];    &#125;&#125;;

再次尝试Dijkstra（完全没必要）需要扔掉dist，在自定义的结构体中保存dis的值，另外，每次出堆的元素的邻接节点不用判断，全部加入堆。
值得注意的是，由于k的限制存在，堆在这道题完全没有作用，反而会有副作用：

假如，题目要求k&#x3D;0，并且答案经过的这条直接相邻的边权值巨高，则堆会将该方法引向歧途
抑或是k的限制，根本不存在答案，需要返回-1，但是由于不加判断，堆会不停进元素，导致死循环

class Item &#123;public:    int node, skip, dis;    Item(int a, int b, int c):node(a),skip(b),dis(c)&#123;&#125;    bool operator&gt;(const Item&amp; R) const &#123;        return this-&gt;dis &gt; R.dis;    &#125;&#125;;class Solution &#123;public:    int INF = 0x3f3f3f3f;    int findCheapestPrice(int n, vector&lt;vector&lt;int&gt;&gt;&amp; flights, int src, int dst, int k) &#123;        vector&lt;vector&lt;pair&lt;int, int&gt;&gt;&gt; g(n);        for (auto&amp; e : flights) g[e[0]].push_back(&#123; e[1], e[2] &#125;);        priority_queue&lt;Item, vector&lt;Item&gt;, greater&lt;Item&gt;&gt; pq;        pq.emplace(src, 0, 0);        while (!pq.empty()) &#123;            auto cur = pq.top(); pq.pop();            int node = cur.node;            int dis = cur.dis;            int skip = cur.skip;            if (node == dst) return dis;            if (skip &gt; k) continue;            for (auto&amp; e : g[node]) &#123;                int w_node = e.first;                int w_weight = e.second;                // 不管，全部加入队列                pq.emplace(w_node, skip + 1, dis + w_weight);            &#125;        &#125;        return -1;    &#125;&#125;;

bellman(邻接矩阵)Bellman Ford 核心操作需要遍历所有的边
class Solution &#123;public:    int INF = 0x3f3f3f3f;    int bf(vector&lt;vector&lt;int&gt;&gt;&amp; g, int src, int dst, int k) &#123;        int n = g.size();        vector&lt;int&gt; dist(g.size(), INF);        dist[src] = 0;        while (k--) &#123;            vector&lt;int&gt; tmp(dist);            for (int i = 0; i &lt; n; ++i) &#123;                for (int j = 0; j &lt; n; ++j) &#123;                    dist[j] = min(dist[j], tmp[i] + g[i][j]);                &#125;            &#125;        &#125;        return dist[dst];    &#125;    int findCheapestPrice(int n, vector&lt;vector&lt;int&gt;&gt;&amp; flights, int src, int dst, int k) &#123;        vector&lt;vector&lt;int&gt;&gt; g(n, vector&lt;int&gt;(n, INF));        for (int i = 0; i &lt; n; ++i) g[i][i] = 0;        for (auto&amp; e : flights) g[e[0]][e[1]] = e[2];        int ret = bf(g, src, dst, k+1);        return ret == INF ? -1 : ret;    &#125;&#125;;

bellman(flights本身就是边)class Solution &#123;public:    int INF = 0x3f3f3f3f;    int bf(vector&lt;vector&lt;int&gt;&gt;&amp; edg, int src, int dst, int k) &#123;        int n = edg.size();        vector&lt;int&gt; dist(edg.size(), INF);        dist[src] = 0;        while (k--) &#123;            vector&lt;int&gt; tmp(dist);            for (int i = 0; i &lt; n; ++i) &#123;                for (auto&amp; e : edg) &#123;                    int x = e[0], y = e[1], w = e[2];                    dist[y] = min(dist[y], tmp[x] + w);                &#125;            &#125;        &#125;        return dist[dst];    &#125;    int findCheapestPrice(int n, vector&lt;vector&lt;int&gt;&gt;&amp; flights, int src, int dst, int k) &#123;        int ret = bf(flights, src, dst, k+1);        return ret == INF ? -1 : ret;    &#125;&#125;;

BFSclass Solution &#123;public:    int INF = 0x3f3f3f3f;    int findCheapestPrice(int n, vector&lt;vector&lt;int&gt;&gt;&amp; flights, int src, int dst, int k) &#123;        vector&lt;vector&lt;pair&lt;int, int&gt;&gt;&gt; g(n);        for (auto&amp; e : flights) g[e[0]].push_back(&#123; e[1], e[2] &#125;);        vector&lt;int&gt; dist(n, INF);        queue&lt;int&gt; q;        q.push(src);        dist[src] = 0;        while (!q.empty() &amp;&amp; k-- &gt;= 0) &#123;            int sz = q.size();            vector&lt;int&gt; tmp(dist); // 保留上一时刻的快照            for (int i = 0; i &lt; sz; ++i) &#123;                int cur = q.front(); q.pop();                for (auto&amp; w : g[cur]) &#123;                    if (dist[w.first] &gt; tmp[cur] + w.second) &#123; // dist!                        dist[w.first] = tmp[cur] + w.second;                        q.push(w.first); // 放到if里面（发生更新时才添加元素）                    &#125;                &#125;            &#125;        &#125;        return dist[dst] == INF ? -1 : dist[dst];    &#125;&#125;;

1 拓扑排序（有向图）课程表Ⅱ1.1 BFS（易理解）创建一个表示入度的数组，初始将入度为0的节点加入队列，后续依次弹出队列，每次弹出node，减小node指向的节点的入度，入度为0的加入队列，直到队列为空，结果需要判定出队列的节点数和图的总节点数相同，不同则代表有循环
class Solution &#123;public:    vector&lt;int&gt; findOrder(int numCourses, vector&lt;vector&lt;int&gt;&gt;&amp; prerequisites) &#123;        vector&lt;vector&lt;int&gt;&gt; g(numCourses);        vector&lt;int&gt; inDegree(numCourses);        for (auto&amp; e : prerequisites) &#123;            g[e[1]].push_back(e[0]);            ++inDegree[e[0]];        &#125;        queue&lt;int&gt; q;        vector&lt;int&gt; ret;        for (int i = 0; i &lt; numCourses; ++i)            if (inDegree[i] == 0) q.push(i);        while (!q.empty()) &#123;            int node = q.front(); q.pop();            ret.push_back(node);            for (auto e : g[node]) &#123;                --inDegree[e];                if (inDegree[e] == 0)                    q.push(e);            &#125;        &#125;        return ret.size() == numCourses ? ret : vector&lt;int&gt;();    &#125;&#125;;

public class Solution &#123;    public int[] FindOrder(int numCourses, int[][] prerequisites) &#123;        List&lt;List&lt;int&gt;&gt; graph = Enumerable.Range(0, numCourses).Select(_ =&gt; new List&lt;int&gt;()).ToList();        int[] inDegress = new int[numCourses];        foreach (var pair in prerequisites) &#123;            graph[pair[1]].Add(pair[0]);            ++inDegress[pair[0]];        &#125;        Queue&lt;int&gt; queue = new();        List&lt;int&gt; result = new();        for (int node = 0; node &lt; numCourses; ++node)            if (inDegress[node] == 0) queue.Enqueue(node);        while (queue.Count &gt; 0) &#123;            int node = queue.Dequeue();            result.Add(node);            foreach (var outNode in graph[node]) &#123;                --inDegress[outNode];                if (inDegress[outNode] == 0)                    queue.Enqueue(outNode);            &#125;        &#125;        return result.Count() == numCourses ? result.ToArray() : Array.Empty&lt;int&gt;();    &#125;&#125;

1.2 DFS（递归）后序遍历的结果进行反转，就是拓扑排序的结果
[2025/11/22]下面的图看起来很像二叉树，其实是图，并且有向图的方向是向上的，看的话应该倒过来，因此代码输出的结果第一个是5，所以最后需要反序一下！

// visited防止重复处理节点// used用来判断成环class Solution &#123;public:    vector&lt;bool&gt; visited; // 不重置    vector&lt;bool&gt; used; // 每次递归，回溯重置    vector&lt;int&gt; postOrder; // 结果数组    // 判断有环，顺便记录下后序遍历的节点    bool isCircle(vector&lt;vector&lt;int&gt;&gt;&amp; g, int node) &#123;        if (used[node]) return true;        if (visited[node]) return false;        visited[node] = true;        used[node] = true;        for (auto e : g[node])            if (isCircle(g, e)) return true; // 有环直接返回        postOrder.push_back(node); // 后序遍历位置（递归后面）        used[node] = false;        return false;    &#125;    vector&lt;int&gt; findOrder(int numCourses, vector&lt;vector&lt;int&gt;&gt;&amp; prerequisites) &#123;        vector&lt;vector&lt;int&gt;&gt; g(numCourses);        for (auto&amp; e : prerequisites) g[e[1]].push_back(e[0]);        visited.resize(numCourses, false);        used.resize(numCourses, false);        for (int i = 0; i &lt; numCourses; ++i)            if (isCircle(g, i)) return vector&lt;int&gt;(); // 有环直接返回        reverse(postOrder.begin(), postOrder.end()); // 最后反序很重要        return postOrder;    &#125;&#125;;

public class Solution &#123;    private static bool HasCircle(HashSet&lt;int&gt; visited, HashSet&lt;int&gt; used, List&lt;List&lt;int&gt;&gt; graph, int node, List&lt;int&gt; ret) &#123;        if (used.Contains(node)) return true;        if (visited.Contains(node)) return false;        visited.Add(node);        used.Add(node);        foreach (var outNode in graph[node])            if (HasCircle(visited, used,graph, outNode, ret)) return true;        ret.Add(node);        used.Remove(node);        return false;    &#125;    public int[] FindOrder(int numCourses, int[][] prerequisites) &#123;        List&lt;List&lt;int&gt;&gt; graph = Enumerable.Range(0, numCourses).Select(_ =&gt; new List&lt;int&gt;()).ToList();        int[] inDegress = new int[numCourses];        foreach (var pair in prerequisites)            graph[pair[1]].Add(pair[0]);        HashSet&lt;int&gt; visited = new();        HashSet&lt;int&gt; used = new();        List&lt;int&gt; ret = new();        for (int i = 0; i &lt; numCourses; ++i)            if (HasCircle(visited, used, graph, i, ret)) return Array.Empty&lt;int&gt;();        return Enumerable.Reverse(ret).ToArray();    &#125;&#125;

2 二分图（无向图）图的节点只有两种颜色：红和蓝，相同颜色不能相邻，判断是否是二分图，可有两种方法：DFS和BFS
可能的二分法2.1 DFS注意visited不要重置
class Solution &#123;public:    vector&lt;bool&gt; visited;    vector&lt;bool&gt; color;    bool core(vector&lt;vector&lt;int&gt;&gt;&amp; g, int node) &#123;        visited[node] = true;        for (auto e : g[node]) &#123;            if (!visited[e]) &#123;                color[e] = !color[node];                if (core(g, e) == false)                    return false;            &#125;            else &#123;                if (color[e] == color[node])                    return false;            &#125;        &#125;        return true;    &#125;    bool possibleBipartition(int n, vector&lt;vector&lt;int&gt;&gt;&amp; dislikes) &#123;        vector&lt;vector&lt;int&gt;&gt; g(n + 1);        for (auto&amp; e : dislikes) &#123;            g[e[0]].push_back(e[1]);            g[e[1]].push_back(e[0]);        &#125;        visited.resize(n + 1, false);        color.resize(n + 1, false);        for (int i = 1; i &lt;= n; ++i) &#123;            if (visited[i]) continue;            if (core(g, i) == false) return false;        &#125;        return true;    &#125;&#125;;
public class Solution&#123;    public bool PossibleBipartition(int n, int[][] dislikes)    &#123;        List&lt;List&lt;int&gt;&gt; graph = Enumerable.Range(0, n).Select(_ =&gt; new List&lt;int&gt;()).ToList();        foreach (var pair in dislikes)        &#123;            graph[pair[1] - 1].Add(pair[0] - 1);            graph[pair[0] - 1].Add(pair[1] - 1);        &#125;        bool[] color = new bool[n];        bool[] visited = new bool[n];        for (int i = 0; i &lt; n; ++ i)        &#123;            if (visited[i]) continue;            if (!DFS(graph, color, visited, i))                return false;        &#125;        return true;    &#125;    private bool DFS(List&lt;List&lt;int&gt;&gt; graph, bool[] color, bool[] visited, int node)    &#123;        visited[node] = true;        foreach (var neighbor in graph[node])        &#123;            if (visited[neighbor])            &#123;                if (color[neighbor] == color[node])                    return false;            &#125;            else            &#123;                color[neighbor] = !color[node];                if (!DFS(graph, color, visited, neighbor))                    return false;            &#125;        &#125;        return true;    &#125;&#125;

2.2 BFSclass Solution &#123;public:    vector&lt;bool&gt; visited;    vector&lt;bool&gt; color;    bool core(vector&lt;vector&lt;int&gt;&gt;&amp; g, int node) &#123;        queue&lt;int&gt; q;        q.push(node);        while (!q.empty()) &#123;            int cur = q.front(); q.pop();            visited[cur] = true;            for (auto e : g[cur]) &#123;                if (!visited[e]) &#123;                    color[e] = !color[cur];                    q.push(e);                &#125;                else &#123;                    if (color[e] == color[cur])                        return false;                &#125;            &#125;        &#125;        return true;    &#125;    bool possibleBipartition(int n, vector&lt;vector&lt;int&gt;&gt;&amp; dislikes) &#123;        vector&lt;vector&lt;int&gt;&gt; g(n + 1);        for (auto&amp; e : dislikes) &#123;            g[e[0]].push_back(e[1]);            g[e[1]].push_back(e[0]);        &#125;        visited.resize(n + 1, false);        color.resize(n + 1, false);        for (int i = 1; i &lt;= n; ++i) &#123;            if (visited[i]) continue;            if (core(g, i) == false) return false;        &#125;        return true;    &#125;&#125;;

public class Solution&#123;    public bool PossibleBipartition(int n, int[][] dislikes)    &#123;        List&lt;List&lt;int&gt;&gt; graph = Enumerable.Range(0, n).Select(_ =&gt; new List&lt;int&gt;()).ToList();        foreach (var pair in dislikes)        &#123;            graph[pair[1] - 1].Add(pair[0] - 1);            graph[pair[0] - 1].Add(pair[1] - 1);        &#125;        Queue&lt;int&gt; queue = new();        bool[] color = new bool[n];        bool[] visited = new bool[n];        for (int i = 0; i &lt; n; ++ i)        &#123;            if (visited[i]) continue;            queue.Clear();            queue.Enqueue(i);            if (!BFS(graph, queue, color, visited))                return false;        &#125;        return true;    &#125;    private bool BFS(List&lt;List&lt;int&gt;&gt; graph, Queue&lt;int&gt; queue, bool[] color, bool[] visited)    &#123;        while (queue.Count &gt; 0)        &#123;            var curNode = queue.Dequeue();            visited[curNode] = true;            foreach (var neighbor in graph[curNode])            &#123;                if (visited[neighbor])                &#123;                    if (color[neighbor] == color[curNode])                        return false;                &#125;                else                &#123;                    color[neighbor] = !color[curNode];                    queue.Enqueue(neighbor);                &#125;            &#125;        &#125;        return true;    &#125;&#125;

