1 寻找峰值找到任意一个峰值，你可以假设 nums[-1] &#x3D; nums[n] &#x3D; -∞ 。
1.1 二分法（不怎么优雅）class Solution &#123;public:    int findPeakElement(vector&lt;int&gt;&amp; nums) &#123;        int l = 0, r = nums.size()-1;        while(l &lt;= r)&#123;            int m = (l + r) / 2;            if(m-1&gt;=0 &amp;&amp; nums[m-1]&gt;nums[m])                r = m - 1;            else if(m+1&lt;nums.size() &amp;&amp; nums[m+1]&gt;nums[m])                l = m + 1;            else                return m;        &#125;        return 0; // 永远不会走    &#125;&#125;;

1.2 二分法（优雅）其实只要搞清楚我们「二分」什么内容，根本不会存在说用哪种方式才能写过的情况。
class Solution &#123;public:    int findPeakElement(vector&lt;int&gt;&amp; nums) &#123;        int l = 0, r = nums.size()-1;        while(l &lt; r)&#123;            int m = (l + r) &gt;&gt; 1;            // 这里m+1不会越界，因为l &lt;= m &lt; r，所以m-1是可能越界的，m+1必然不会越界            if(nums[m] &gt; nums[m+1])                r = m;  // 注意            else                l = m + 1;  // 注意        &#125;        return l;    &#125;&#125;;

2 搜索旋转排序数组（无重复）2.1 二分法（有点丑，但好理解）class Solution &#123;public:    int search(vector&lt;int&gt;&amp; nums, int target) &#123;        int n = nums.size(), l = 0, r = n - 1;        while(l &lt;= r)&#123;            int m = (l + r) &gt;&gt; 1;            if(nums[m] == target) return m;                        // 因为如果就俩数，除以二肯定l == m, r == m+1            if(nums[l] == nums[m])&#123;                if(r &lt; n &amp;&amp; nums[r] == target) return r;                else return -1;            &#125;            else if(nums[l] &lt; nums[m])&#123; // 左边正常                if(target &gt;= nums[l] &amp;&amp; target &lt; nums[m])                     r = m - 1;                else                     l = m + 1;            &#125;            else&#123; // 右边正常                if(target &gt; nums[m] &amp;&amp; target &lt;= nums[r])                    l = m + 1;                else                    r = m - 1;            &#125;        &#125;        return -1;    &#125;&#125;;

2.2 二分法（优雅）（与l比较）
牢记：左区间是[l, m]，右区间是(m+1, r]，所以“左区间正常”包含等号
由于前一步 if(nums[m] == target) return m; 已经判定了nums[m] != target，所以后面对target和nums[m]的比较不带等号

class Solution &#123;public:    int search(vector&lt;int&gt;&amp; nums, int target) &#123;        int n = nums.size(), l = 0, r = n - 1;        while(l &lt;= r)&#123;            int m = (l + r) &gt;&gt; 1;            if(nums[m] == target) return m;            if(nums[l] &lt;= nums[m])&#123; // 左边正常                if(target &gt;= nums[l] &amp;&amp; target &lt; nums[m])                     r = m - 1;                else                     l = m + 1;            &#125;            else&#123; // 右边正常                if(target &gt; nums[m] &amp;&amp; target &lt;= nums[r])                    l = m + 1;                else                    r = m - 1;            &#125;        &#125;        return -1;    &#125;&#125;;

2022.08.10（与r比较）// while等号和不等号class Solution &#123;public:    int search(const vectorr&lt;int&gt;&amp; arr, int target) &#123;        int l = 0, r = arr.size() - 1;        while(l &lt; r)&#123;            int m = (l+r)/2;            if(arr[m] == target) return m;            if(arr[m] &lt; arr[r])&#123; // 右边正常（互不相同所以没等于）                if(target &gt; arr[m] &amp;&amp; target&lt;=arr[r]) l = m + 1;                else r = m - 1;            &#125;else&#123; // 左边正常                if(target &gt;= arr[l] &amp;&amp; target&lt;arr[m]) r = m - 1;                else l = m + 1;            &#125;        &#125;        return arr[l] == target ? l : -1;    &#125;&#125;;class Solution &#123;public:    int search(vector&lt;int&gt;&amp; arr, int target) &#123;        int l = 0, r = arr.size() - 1;        while(l &lt;= r)&#123;            int m = (l+r)/2;            if(arr[m] == target) return m;            if(arr[m] &lt; arr[r])&#123; // 右边正常（互不相同所以没等于）                if(target &gt; arr[m] &amp;&amp; target&lt;=arr[r]) l = m + 1;                else r = m - 1;            &#125;else&#123; // 左边正常                if(target &gt;= arr[l] &amp;&amp; target&lt;arr[m]) r = m - 1;                else l = m + 1;            &#125;        &#125;        return -1;    &#125;&#125;;

3 寻找旋转排序数组中的最小值（无重复）
3.1 二分法
如上图所示，如果每次以nums[l] &lt; nums[m]为条件虽然可以认定左区间是单调的，但是就全局最小值而言无法区分图1和图2的；但是以nums[m] &lt; nums[r]可以认定右区间单调，且可以区分所有最小值情况。一定要理解二分时收缩区间的含义。
不能动不动l = m + 1，r = m - 1这种大起大和的方式，因为目的是求极值而不是target，target不等于的时候，某一边确实可以跳；但是求极值时，例如下面代码中r = m，因为不确定nums[m]是不是极值，所以不能写成r = m - 1

class Solution &#123;public:    int findMin(vector&lt;int&gt;&amp; nums) &#123;        int l = 0, r = nums.size()-1;        while(l &lt; r)&#123;            int m = (l + r) / 2;            if(nums[m] &lt; nums[r])                r = m; // 注意            else                l = m + 1;  // 注意        &#125;        return nums[l];    &#125;&#125;;


为什么左右不对称？为什么比较mid与right而不比较mid与left？能不能通过比较mid与left来解决问题？左右不对称的原因是：这是循环前升序排列的数，左边的数小，右边的数大，而且我们要找的是最小值，肯定是偏向左找，所以左右不对称了。为什么比较mid与right而不比较mid与left？具体原因前面已经分析过了，简单讲就是因为我们找最小值，要偏向左找，目标值右边的情况会比较简单，容易区分，所以比较mid与right而不比较mid与left。那么能不能通过比较mid与left来解决问题？能，转换思路，不直接找最小值，而是先找最大值，最大值偏右，可以通过比较mid与left来找到最大值，最大值向右移动一位就是最小值了（需要考虑最大值在最右边的情况，右移一位后对数组长度取余）。

4 寻找旋转排序数组中的最小值 II（有重复）4.1 二分由于相等时无法确认二分的方向，所以选择慎重地小幅度收缩1步
class Solution &#123;public:    int findMin(vector&lt;int&gt;&amp; arr) &#123;        int l = 0, r = arr.size()-1;        while(l &lt; r)&#123;            int m = (l + r) / 2;            if(arr[m] &lt; arr[r]) r = m;            else if(arr[m] &gt; arr[r]) l = m + 1;            else --r;        &#125;        return arr[l];    &#125;&#125;;

4.2 栈+二分由于相等时无法确认二分的方向，所以用栈保存下来可能的区间，留作继续二分
class Solution &#123;public:    int findMin(vector&lt;int&gt;&amp; arr) &#123;        stack&lt;int&gt; stk;        stk.push(0);        stk.push(arr.size()-1);        int l=0, r=0;        int res = 0x3f3f3f3f;        while(!stk.empty())&#123;            r = stk.top(); stk.pop();            l = stk.top(); stk.pop();            while(l &lt; r)&#123;                int m = (l + r) / 2;                if(arr[m] == arr[r])&#123;                    stk.push(l);                    stk.push(m-1);                    l = m + 1;                &#125;else if(arr[m] &lt; arr[r])&#123;                    r = m;                &#125;else if(arr[m] &gt; arr[r])&#123;                    l = m + 1;                &#125;            &#125;            if(l &lt;= r) // !                res = min(res, arr[r]);        &#125;        return res;    &#125;&#125;;

32 最长有效括号方法1：动态规划1.1 错误1无法解决诸如(())的问题。 要考虑到当前碰到右括号后，前面的是左括号还是右括号，然后分别进行处理
class Solution &#123;public:    int longestValidParentheses(string s) &#123;        int n = s.size();        int l = 0;        vector&lt;int&gt; dp(n);        int ret = 0;        for(int i=0; i&lt;n; ++i)&#123;            if(s[i] == &#x27;(&#x27;)&#123;                ++l;                 continue;            &#125;            if(l)&#123;                --l;                dp[i] = 2;                if(i-2 &gt;= 0) dp[i] += dp[i-2]; // BUG                ret = max(ret, dp[i]);            &#125;        &#125;        return ret;    &#125;&#125;;

1.2 错误2无法解决诸如()(())的问题。 

*****() 好解决直接 dp[i] += dp[i-2];
*****)) 需要额外判断找到与当前右括号i对应的左括号t，然后t的左边要继续判断

class Solution &#123;public:    int longestValidParentheses(string s) &#123;        int n = s.size();        int l = 0;        vector&lt;int&gt; dp(n);        int ret = 0;        for(int i=0; i&lt;n; ++i)&#123;            if(s[i] == &#x27;(&#x27;)&#123;                ++l;                 continue;            &#125;            if(l)&#123;                --l;                dp[i] = 2;                if(s[i-1] == &#x27;(&#x27; &amp;&amp; i-2 &gt;= 0) dp[i] += dp[i-2];                else if(s[i-1] == &#x27;)&#x27;) dp[i] += dp[i-1]; // 这里要继续修改                ret = max(ret, dp[i]);            &#125;        &#125;        return ret;    &#125;&#125;;

1.3 正确答案class Solution &#123;public:    int longestValidParentheses(string s) &#123;        int n = s.size();        int l = 0;        vector&lt;int&gt; dp(n);        int ret = 0;        for(int i=0; i&lt;n; ++i)&#123;            if(s[i] == &#x27;(&#x27;)&#123;                ++l;                 continue;            &#125;            if(l)&#123;                --l;                dp[i] = 2;                if(s[i-1] == &#x27;(&#x27; &amp;&amp; i-2 &gt;= 0) dp[i] += dp[i-2];                else if(s[i-1] == &#x27;)&#x27;)&#123;                    dp[i] += dp[i-1];                    if(i-dp[i]&gt;=0) //添加这里                        dp[i] += dp[i-dp[i]];                &#125;                ret = max(ret, dp[i]);            &#125;        &#125;        return ret;    &#125;&#125;;

1.4 官方的DP（LC官方）(Elegant)class Solution &#123;public:    int longestValidParentheses(string s) &#123;        int n = s.size();        vector&lt;int&gt; dp(n, 0);        int res = 0;        for(int i=1; i&lt;n; ++i)&#123;            if(s[i] == &#x27;(&#x27;) continue;            // 只有以&#x27;)&#x27;结尾的才有效            if(s[i-1] == &#x27;(&#x27;)&#123;                if(i-2 &lt; 0) dp[i] = 2; // 防止越界                else dp[i] = dp[i-2] + 2; // 转移函数            &#125;else&#123;                if(i-dp[i-1]-1&gt;=0 &amp;&amp; s[i-dp[i-1]-1] == &#x27;(&#x27;)&#123;                    dp[i] = dp[i-1] + 2; // 转移函数                    if(i-dp[i-1]-2 &gt;= 0)                        dp[i] += dp[i-dp[i-1]-2];                &#125;            &#125;            res = max(res, dp[i]);        &#125;        return res;    &#125;&#125;;

方法2：栈（LC官方）保持栈底元素为当前已经遍历过的元素中 「最后一个没有被匹配的右括号的下标」 需要注意的是，如果一开始栈为空，第一个字符为左括号的时候我们会将其放入栈中，这样就不满足提及的「最后一个没有被匹配的右括号的下标」，为了保持统一，我们在一开始的时候往栈中放入一个值为 -1−1 的元素。
class Solution &#123;public:    int longestValidParentheses(string s) &#123;        int n = s.size();        stack&lt;int&gt; stk;        stk.push(-1);        int res = 0;        for(int i=0; i&lt;n; ++i)&#123;            if(s[i] == &#x27;(&#x27;) stk.push(i);            else&#123;                stk.pop();                if(stk.empty()) // 更新「最后一个没有被匹配的右括号的下标」                    stk.push(i);                else                    res = max(res, i-stk.top()); // 以i结尾的有效性括号长度            &#125;        &#125;        return res;    &#125;&#125;;

方法3：贪心（LC官方）利用两个计数器l和r，从左到右遍历字符串，遇到左括号则l加1，遇到右括号则r加1；当l和r相等时更新最长长度，当r&gt;l时将l和r置0
这样的做法贪心地考虑了以当前字符下标结尾的有效括号长度，每次当右括号数量多于左括号数量的时候之前的字符我们都扔掉不再考虑，重新从下一个字符开始计算，但这样会漏掉一种情况，就是遍历的时候左括号的数量始终大于右括号的数量，即 (() ，这种时候最长有效括号是求不出来的。
解决的方法也很简单，我们只需要从右往左遍历用类似的方法计算即可，只是这个时候判断条件反了过来：当r&lt;l时将l和r置0。
这样我们就能涵盖所有情况从而求解出答案。
class Solution &#123;public:    int longestValidParentheses(string s) &#123;        int l = 0, r = 0;        int res = 0;        for(int i=0; i&lt;s.size(); ++i)&#123;            if(s[i] == &#x27;(&#x27;) ++l;            else ++r;            if(l == r) res = max(res, l + r);            else if(r &gt; l) l = r = 0;        &#125;        l = r = 0; // 重置！        for(int i=s.size()-1; i&gt;=0; --i)&#123;            if(s[i] == &#x27;(&#x27;) ++l;            else ++r;            if(l == r) res = max(res, l + r);            else if(l &gt; r) l = r = 0;        &#125;        return res;    &#125;&#125;;

1143 最长公共子序列
子序列是可以不连续的
dp[i][j]的含义是text1[:i]和text2[:j]最长公共子序列，这个最长公共子序列不一定包含text1[i]和text2[j]

class Solution &#123;public:    int longestCommonSubsequence(string text1, string text2) &#123;        int m = text1.size(), n = text2.size();        vector&lt;vector&lt;int&gt;&gt; dp(m+1, vector&lt;int&gt;(n+1, 0)); // 多一行一列        for(int i=1; i&lt;=m; ++i)&#123;            for(int j=1; j&lt;=n; ++j)&#123;                if(text1[i-1] == text2[j-1]) dp[i][j] = dp[i-1][j-1] + 1; // 别忘了坐标偏移                else dp[i][j] = max(dp[i-1][j], dp[i][j-1]);            &#125;        &#125;        return dp[m][n];    &#125;&#125;;

718 最长重复子数组
子数组是连续的
dp[i][j]的含义是以nums1[i]结尾的nums1[:i]和以nums2[j]结尾的nums2[:j]的最长重复子数组

class Solution &#123;public:    int findLength(vector&lt;int&gt;&amp; nums1, vector&lt;int&gt;&amp; nums2) &#123;        int m = nums1.size(), n = nums2.size();        vector&lt;vector&lt;int&gt;&gt; dp(m+1, vector&lt;int&gt;(n+1, 0));        int ret = 0;        for(int i=1; i&lt;=m; ++i)&#123;            for(int j=1; j&lt;=n; ++j)&#123;                if(nums1[i-1] == nums2[j-1])&#123;                    dp[i][j] = dp[i-1][j-1] + 1;                    ret = max(ret, dp[i][j]);                &#125;            &#125;        &#125;        return ret;    &#125;&#125;;

