Prim：从一颗小树长大思路和Dijkstra基本一致，唯一不同就是dist记录的是与集合的距离而非与起点的距离
// Leetcode 1584 连接所有点的最小费用// points = [[0,0],[2,2],[3,10],[5,2],[7,0]] 求坐标轴上这几个点的最小生成树的路径和struct Node&#123; // 用来在优先队列里用    int node;    int dis;    bool operator&gt;(const Node&amp; ano) const &#123;        return this-&gt;dis &gt; ano.dis;    &#125;&#125;;class Solution &#123;public:    int minCostConnectPoints(vector&lt;vector&lt;int&gt;&gt;&amp; points) &#123;        int n = points.size(); // 节点数        vector&lt;vector&lt;int&gt;&gt; graph(n, vector&lt;int&gt;(n, INT_MAX));        for (int i = 0; i &lt; n; ++i)&#123; // 建图            for (int j = 0; j &lt; i; ++j)&#123;                graph[i][j] = abs(points[i][0]-points[j][0]) + abs(points[i][1]-points[j][1]);                graph[j][i] = graph[i][j];            &#125;        &#125;          priority_queue&lt;Node, vector&lt;Node&gt;, greater&lt;Node&gt;&gt; pq;        vector&lt;int&gt; dist(n, INT_MAX);        pq.push(Node(&#123;0, 0&#125;)); // 从0开始， 0到0的距离是0        int ret = 0;        while(!pq.empty())&#123;            Node cur = pq.top(); pq.pop();            // 跟Dijkstra一样，但人家遇到终点直接可以break            // 因为采用优先队列的方式，队列里会有重复，第一次接触的肯定是最优解，后面            // 重复的都是大于最优解的，直接跳过，或者你用一个数组，存储对应节点最优dist            // 每次存储比较取最小值，但是空间浪费太大了，不如这样好            if(dist[cur.node] == 0) continue;            dist[cur.node] = 0;            ret += cur.dis;            for(int i=0; i&lt;n; ++i)&#123;                if(dist[i] &gt; graph[cur.node][i])&#123;                    dist[i] = graph[cur.node][i];                    pq.push(Node(&#123;i, graph[cur.node][i]&#125;));                &#125;            &#125;        &#125;        return ret;    &#125;&#125;;

Kruskal利用并查集的思想
// Leetcode 1584 连接所有点的最小费用// points = [[0,0],[2,2],[3,10],[5,2],[7,0]] 求坐标轴上这几个点的最小生成树的路径和class UFSet&#123;public:    UFSet(int _n):count(_n), parent(_n, -1)&#123;&#125;    int getCount()&#123;return count;&#125;    void unite(int a, int b)&#123;        int f1 = find(a);        int f2 = find(b);        if(f1 == f2) return;        if(parent[f1] &lt; parent[f2])&#123;            parent[f1] += parent[f2];            parent[f2] = f1;        &#125;else&#123;            parent[f2] += parent[f1];            parent[f1] = f2;        &#125;        -- count;    &#125;    bool isConnected(int a, int b)&#123;        return find(a) == find(b);    &#125;    private:    int find(int pos)&#123;        if(parent[pos] &lt; 0) return pos;        return parent[pos] = find(parent[pos]);    &#125;    int count; // 连通集的个数    vector&lt;int&gt; parent;&#125;;struct Edge&#123;    int from;    int to;    int weight;    bool operator&gt;(const Edge&amp; ano) const &#123;        return this-&gt;weight &gt; ano.weight;    &#125;&#125;;class Solution &#123;public:    // 都不用建图，直接把边放进去就行了    int minCostConnectPoints(vector&lt;vector&lt;int&gt;&gt;&amp; points) &#123;        int n = points.size();        UFSet ufs(n);        priority_queue&lt;Edge, vector&lt;Edge&gt;, greater&lt;Edge&gt;&gt; pq;        for(int i=0; i&lt;n; ++i)&#123;            for(int j=0; j&lt;i; ++j)&#123;                int weight = abs(points[i][0]-points[j][0]) + abs(points[i][1]-points[j][1]);                pq.push(Edge(&#123;i, j, weight&#125;));            &#125;        &#125;        int res = 0, cnt = 0;        while(!pq.empty() &amp;&amp; cnt&lt;n-1)&#123;            Edge cur = pq.top(); pq.pop();            if(ufs.isConnected(cur.from, cur.to) == false)&#123; // from和to是图节点名，这里直接以points顺序的下标来表示                ufs.unite(cur.from, cur.to);                res += cur.weight;                ++cnt;            &#125;        &#125;        return res;    &#125;&#125;;

01背包经典动态规划问题，输入重量数组weight、价值数组value和背包可承载的最大重量整数maxW
class Solution &#123;public:	int knapsack(vector&lt;int&gt;&amp; weight, vector&lt;int&gt;&amp; value, int maxW) &#123;		// 物品数目		int kinds = weight.size();		// dp数组初始化为二维数组		vector&lt;vector&lt;int&gt;&gt; dp(kinds + 1, vector&lt;int&gt;(maxW + 1, 0));		// 状态一：可选的目标：0个可选，前一个可选、前两个可选、前三个可选，以此类推（与找零钱不同，物品不能重复选）		for (int c = 1; c &lt;= kinds; c++) &#123;			// 状态二：当前的可承载重量，0、1、2...maxW			for (int w = 1; w &lt;= maxW; w++) &#123;				// 该物品太大以至于当前重量超标：下标越界，直接赋值为“没有该物品时的最优答案”				if (w - weight[c - 1] &lt; 0) 					dp[c][w] = dp[c - 1][w];				// 比较，“不选择该物品”和“选择该物品”时，哪个价值大				else					dp[c][w] = max(dp[c - 1][w], dp[c - 1][w - weight[c - 1]] + value[c - 1]);			&#125;		&#125;		return dp[kinds][maxW];	&#125;&#125;;

完全背包标准DPclass Solution &#123;public:    int change(int amount, vector&lt;int&gt;&amp; coins) &#123;        int n = coins.size();        vector&lt;vector&lt;int&gt;&gt; dp(n+1, vector&lt;int&gt;(amount+1, 0));		// base case 这里也可以只dp[0][0]=1，但下面的二重循环的j必须从0开始了		// 从含义上来说，还是在这里初始化一列全1比较符合定义		for(int s = 0; s&lt;=n; ++s)			dp[s][0] = 1;        for(int i=1; i&lt;=n; ++i)&#123;            for(int j=1; j&lt;=amount; ++j)&#123;                if(coins[i-1] &gt; j)					dp[i][j] = dp[i-1][j];                else // dp[i][j] = dp[i-1][j] + dp[i-1][j-coins[i-1]];一个数字之差就变成不可重复选取了                    dp[i][j] = dp[i-1][j] + dp[i][j-coins[i-1]];            &#125;        &#125;        return dp[n][amount];    &#125;&#125;;

压缩一下class Solution &#123;public:    int change(int amount, vector&lt;int&gt;&amp; coins) &#123;        int n = coins.size();        vector&lt;int&gt; dp(amount+1, 0);		dp[0] = 1;        for(int i=1; i&lt;=n; ++i)&#123;            for(int j=1; j&lt;=amount; ++j)&#123;                if(coins[i-1] &lt;= j)                    dp[j] = dp[j] + dp[j-coins[i-1]]; // 由于需要用到当前行更新的值，正好不用倒过来了，和下面子集背包压缩做对比            &#125;        &#125;        return dp[amount];    &#125;&#125;;

子集背包标准DP// 子集背包问题class Solution &#123;public:    // sum(A1) == sum(A2) -&gt; target = sum(A)/2    bool canPartition(vector&lt;int&gt;&amp; nums) &#123;        int sum = 0;        for (auto e : nums) sum += e;        if (sum % 2) // 和必须是偶数            return false;        int target = sum &gt;&gt; 1;        int n = nums.size();        vector&lt;vector&lt;bool&gt;&gt; dp(n + 1, vector&lt;bool&gt;(target + 1, 0)); // 用布尔        dp[0][0] = 1; // 初始化        for (int i = 1; i &lt;= n; i++) &#123;            for (int j = 0; j &lt;= target; j++) &#123;                if (nums[i - 1] &gt; j)                    dp[i][j] = dp[i - 1][j];                else                    dp[i][j] = dp[i - 1][j] + dp[i - 1][j - nums[i - 1]];            &#125;        &#125;        return dp[n][target] &gt; 0;    &#125;&#125;;

压缩一下// 子集背包问题class Solution &#123;public:    // sum(A1) == sum(A2) -&gt; target = sum(A)/2    bool canPartition(vector&lt;int&gt;&amp; nums) &#123;        int sum = 0;        for (auto e : nums) sum += e;        if (sum % 2) // 和必须是偶数            return false;        int target = sum &gt;&gt; 1;        int n = nums.size();        vector&lt;bool&gt; dp(target + 1, false); // 用布尔        dp[0] = true; // 初始化        for (int i = 1; i &lt;= n; i++) &#123;            for (int j = target; j &gt;= 0; j--) &#123; // 必须从后往前，不然会覆盖之前的数据                if (nums[i - 1] &gt; j)                    dp[j] = dp[j];                else                    dp[j] = dp[j] || dp[j - nums[i - 1]];            &#125;        &#125;        return dp[target] &gt; 0;    &#125;&#125;;

