1、普通版本（高并发效率不足）（安全）
在类中添加一个私有静态成员单例实例的指针。
声明一个公有静态构建方法用于获取单例实例的指针。
在静态方法中实现”延迟初始化”。 该方法会在首次被调用时创建一个新对象， 并将其存储在静态成员变量中。 此后该方法每次被调用时都返回该实例。
将类的构造函数设为私有。 类的静态方法仍能调用构造函数， 但是其他对象不能调用。
检查客户端代码， 将对单例的构造函数的调用替换为对其静态构建方法的调用。

class Singleton &#123;protected:	Singleton(const string&amp; val) : data(val) &#123;&#125; // 构造函数	~Singleton() &#123;&#125;	static Singleton* _instance; // 静态：实例的指针	static mutex _mutex;	string data; // 代表类内的资源public:	Singleton(const Singleton&amp; another) = delete; // 禁止拷贝构造	Singleton&amp; operator=(const Singleton&amp; another) = delete; // 禁止赋值	static Singleton* getInstance(const string&amp; val); // 静态：获取实例	void show() &#123; cout &lt;&lt; &quot;data: &quot; &lt;&lt; data &lt;&lt; endl; &#125; // 测试&#125;;// 静态成员需要在类外定义Singleton* Singleton::_instance = nullptr;mutex Singleton::_mutex;Singleton* Singleton::getInstance(const string&amp; val) &#123;	lock_guard&lt;mutex&gt; lock(_mutex); // 出作用域自动释放	if (_instance == nullptr) &#123;		_instance = new Singleton(val);	&#125;	return _instance;&#125;int main() &#123;	Singleton* a = Singleton::getInstance(&quot;aaa&quot;);	a-&gt;show(); // &quot;aaa&quot; ok	Singleton* b = Singleton::getInstance(&quot;bbb&quot;);	b-&gt;show(); // &quot;aaa&quot; ok	return 0;&#125;

2、双检查锁（有隐患）reorder问题：通常new通常有三步：1、分配一块内存空间；2、执行构造器；3、返回指针；但是由于编译器有时会进行优化，执行顺序变为132：即分配空间后先返回指针，再执行构造器这样就会到来危险，比如线程A执行new，132，3执行完；线程B发现m_instance非空返回，然后外部直接用这个指针会出错
//双检查锁，但由于内存读写reorder不安全（不安全）Singleton* Singleton::getInstance() &#123;    if(m_instance==nullptr)&#123; // 第一次检查，主要解决性能问题，毕竟读操作不需要上锁        Lock lock;        if (m_instance == nullptr) &#123; // 第二次检查，解决核心问题：只能new单个            m_instance = new Singleton();        &#125;    &#125;    return m_instance;&#125;

3、双检查锁（安全）//C++ 11版本之后的跨平台实现 (volatile)（安全）std::atomic&lt;Singleton*&gt; Singleton::m_instance;std::mutex Singleton::m_mutex;Singleton* Singleton::getInstance() &#123;    Singleton* tmp = m_instance.load(std::memory_order_relaxed);    std::atomic_thread_fence(std::memory_order_acquire); // 获取内存fence    if (tmp == nullptr) &#123;        std::lock_guard&lt;std::mutex&gt; lock(m_mutex);        tmp = m_instance.load(std::memory_order_relaxed);        if (tmp == nullptr) &#123;            tmp = new Singleton;            std::atomic_thread_fence(std::memory_order_release); // 释放内存fence            m_instance.store(tmp, std::memory_order_relaxed);        &#125;    &#125;    return tmp;&#125;

