// MainForm.cppclass MainForm : public Form&#123;	TextBox* txtFilePath;	TextBox* txtFileNumber;	ProgressBar* progressBar;public:	void Button1_Click()&#123;		string filePath = txtFilePath-&gt;getText();		int number = atoi(txtFileNumber-&gt;getText().c_str());		FileSplitter splitter(filePath, number, progressBar);		splitter.split();	&#125;&#125;;

3 观察者v1
// FileSplitter.cppclass FileSplitter&#123;	string m_filePath;	int m_fileNumber;	List&lt;IProgress*&gt;  m_iprogressList; // 抽象通知机制，支持注册多个观察者！！！	public:	FileSplitter(const string&amp; filePath, int fileNumber) :		m_filePath(filePath), 		m_fileNumber(fileNumber)&#123;	&#125;	void split()&#123;		//1.读取大文件		// ...		//2.分批次向小文件中写入		for (int i = 0; i &lt; m_fileNumber; i++)&#123;			//...			float progressValue = m_fileNumber;			progressValue = (i + 1) / progressValue;			onProgress(progressValue); // 发送通知		&#125;	&#125;	void addIProgress(IProgress* iprogress)&#123; // 添加观察者		m_iprogressList.push_back(iprogress);	&#125;	void removeIProgress(IProgress* iprogress)&#123; // 移除观察者		m_iprogressList.remove(iprogress);	&#125;protected:	virtual void onProgress(float value)&#123;		List&lt;IProgress*&gt;::iterator itor=m_iprogressList.begin();		while (itor != m_iprogressList.end())			(*itor)-&gt;DoProgress(value); //更新进度条			itor++;		&#125;	&#125;&#125;;

// MainForm.cppclass IProgress&#123;public:	virtual void DoProgress(float value)=0;	virtual ~IProgress()&#123;&#125;&#125;;// C++不推荐多继承，但是推荐的唯一一种多继承的形式是：一个主集成、其他都是接口或者抽象基类// MainForm是观察者class MainForm : public Form, public IProgress&#123;	TextBox* txtFilePath;	TextBox* txtFileNumber;	ProgressBar* progressBar;public:	void Button1_Click()&#123;		string filePath = txtFilePath-&gt;getText();		int number = atoi(txtFileNumber-&gt;getText().c_str());		FileSplitter splitter(filePath, number);		splitter.addIProgress(this); // 订阅通知		ConsoleNotifier cn; // 观察者二		splitter.addIProgress(&amp;cn); // 订阅通知		splitter.split();		splitter.removeIProgress(this);	&#125;	virtual void DoProgress(float value)&#123;		progressBar-&gt;setValue(value);	&#125;&#125;;// 另一个观察者class ConsoleNotifier : public IProgress &#123;public:	virtual void DoProgress(float value)&#123;		cout &lt;&lt; &quot;.&quot;; // 无UI：打点	&#125;&#125;;

4 观察者v2（可执行）#include &quot;Header.h&quot;#include &lt;random&gt;#include &lt;thread&gt;class NumGen;class NumGenObserver &#123;public:	virtual ~NumGenObserver() &#123;&#125;	virtual void update(NumGen *numGen) = 0;&#125;;class NumGen &#123;public:	virtual ~NumGen() &#123;&#125;	void addObserve(NumGenObserver *observe) &#123;		m_observeList.push_back(observe);	&#125;	void deleteObserve(NumGenObserver *observe) &#123;		m_observeList.erase(std::remove(m_observeList.begin(), m_observeList.end(), observe));	&#125;	void notifyObverses() &#123;		for (auto gen : m_observeList) &#123;			gen-&gt;update(this);		&#125;	&#125;	virtual int getNumber() = 0;	virtual void execute() = 0;private:	std::vector&lt;NumGenObserver *&gt; m_observeList;&#125;;class RandomNumGen : public NumGen &#123;public:	virtual int getNumber() override &#123;		return m_number;	&#125;	virtual void execute() override &#123;		for (int i = 0; i &lt; 20; ++i) &#123;			m_number = m_dis(m_gen);			notifyObverses();		&#125;	&#125;private:	std::random_device m_rd;	std::mt19937 m_gen&#123; m_rd() &#125;;	std::uniform_int_distribution&lt;int&gt; m_dis&#123; 0, 100 &#125;;	int m_number&#123; 0 &#125;;&#125;;class DigitObserver : public NumGenObserver &#123;public:	virtual void update(NumGen *numGen) override &#123;		std::cout &lt;&lt; &quot;DigitObserver:&quot;;		std::cout &lt;&lt; numGen-&gt;getNumber() &lt;&lt; std::endl;		std::this_thread::sleep_for(std::chrono::milliseconds(10));	&#125;&#125;;class GraphObserver : public NumGenObserver &#123;public:	virtual void update(NumGen *numGen) override &#123;		auto num = numGen-&gt;getNumber();		std::cout &lt;&lt; &quot;GraphObserver:&quot;;		for (int i = 0; i &lt; num; ++i) &#123;			std::cout &lt;&lt; &quot;*&quot;;		&#125;		std::cout &lt;&lt; std::endl;		std::this_thread::sleep_for(std::chrono::milliseconds(10));	&#125;&#125;;int main() &#123;	NumGen *gen = new RandomNumGen;	NumGenObserver *ob1 = new DigitObserver;	NumGenObserver *ob2 = new GraphObserver;	gen-&gt;addObserve(ob1);	gen-&gt;addObserve(ob2);	gen-&gt;execute();	delete gen;	delete ob1;	delete ob2;	return 0;&#125;

5 观察者v3（配合模板更通用的观察者模式）template&lt;typename ObserverType&gt;class Subject &#123;    vector&lt;ObserverType*&gt; _list;public:    // 订阅    void subscribe(ObserverType* obs) &#123;        auto itor = std::find(_list.begin(), _list.end(), obs);        if (_list.end() == itor) &#123;            _list.push_back(obs);        &#125;    &#125;        // 取消订阅    void unSubscribe(ObserverType* obs) &#123;        // erase配合remove        _list.erase(std::remove(_list.begin(), _list.end(), obs));    &#125;    // 发布    template&lt;typename FuncType&gt;    void publish(FuncType func) &#123;        for (auto obs : _list) &#123;            // 调用回调函数，将obs作为一个参数传入            func(obs);        &#125;    &#125;&#125;;// CatObserver接口 猫的观察者class CatObserver &#123;public:    virtual void onMiaow() = 0;    virtual ~CatObserver() &#123;&#125;&#125;;// Tom继承自Subject，模板参数CatObserver// 这样Tom就可以订阅、发布对应类型class Tom : public Subject&lt;CatObserver&gt; &#123;public:    void miaow() &#123;        cout &lt;&lt; &quot;喵&quot; &lt;&lt; endl;        // 这里CatObserver的成员函数，所以第一个参数需要this指针，这里悬置-&gt;对应publish的object        publish(std::bind(&amp;CatObserver::onMiaow, std::placeholders::_1));    &#125;&#125;;// Jerry继承自CatObserver，可以被订阅class Jerry : public CatObserver &#123;public:    void onMiaow() override &#123;        RunAway();    &#125;    void RunAway() &#123;        cout &lt;&lt; &quot;那只笨又猫来了，快跑！&quot; &lt;&lt; endl;    &#125;&#125;;int main() &#123;    Tom tom;    Jerry jerry1, jerry2, jerry3;    // 拿一堆jerry去订阅tom的 猫叫 事件    tom.subscribe(&amp;jerry1);    tom.subscribe(&amp;jerry2);    tom.subscribe(&amp;jerry3);        tom.miaow();&#125;
输出结果：
喵那只笨又猫来了，快跑！那只笨又猫来了，快跑！那只笨又猫来了，快跑！

6 总结
使用面向对象的抽象，Observer模式使得我们可以独立地改变目标与观察者，从而使二者之间的依赖关系达致松耦合。
目标发送通知时，无需指定观察者，通知（可以携带通知信息作为参数）会自动传播。
观察者自己决定是否需要订阅通知，目标对象对此一无所知。
Observer模式是基于事件的UI框架中非常常用的设计模式，也是MVC模式的一个重要组成部分。

