当右侧当前指针指向位置的数字CUR较小时，本轮将其加入归并后的数组，注意到左数组当前指针及其右边都是大于CUR的，但是他们的位置却在其左侧，所以逆序对的贡献为old_l2 - l1
if (a &lt;= b)  // 这里包含等于 可以用全1数组模拟想想    trr[p++] = arr[l1++];else &#123;    trr[p++] = arr[l2++];    ret += (old_l2 - l1);&#125;
下面是完整代码
class Solution &#123;public:    int ret = 0;    void merge(vector&lt;int&gt;&amp; arr, vector&lt;int&gt;&amp; trr, int l1, int r1, int l2, int r2) &#123;        int l = l1, r = r2;        int p = l1, old_l2 = l2;        while (l1 &lt;= r1 || l2 &lt;= r2) &#123;            long long a = l1 &lt;= r1 ? arr[l1] : LLONG_MAX;            long long b = l2 &lt;= r2 ? arr[l2] : LLONG_MAX;            if (a &lt;= b) &#123; // !!!!! &lt;= 等于时也必须，不然右侧添加一堆等于的，再计算，结果肯定大了呀                trr[p++] = arr[l1++];                ret += (l2-old_l2); // 只需要在这里加上这句，收集逆序对            &#125;            else                 trr[p++] = arr[l2++];        &#125;        for (int i = l; i &lt;= r; ++i)            arr[i] = trr[i];    &#125;    void core(vector&lt;int&gt;&amp; arr, vector&lt;int&gt;&amp; trr, int l, int r) &#123;        if (l &gt;= r) return;        int m = (l + r) / 2;        core(arr, trr, l, m);        core(arr, trr, m + 1, r);        merge(arr, trr, l, m, m + 1, r);    &#125;    int reversePairs(vector&lt;int&gt;&amp; nums) &#123;        vector&lt;int&gt; trr(nums.size());        core(nums, trr, 0, (int)nums.size() - 1);        return ret;    &#125;&#125;;

2 离散化+树状数组树状数组可以非常方便进行区间统计和单点修改，对于原数组，我们从后往前遍历，依次将其加入树状数组（计数），并求其左侧（小于的）之前的所有已插入的数字的和，最终即可求得总的逆序对。然而，原数组的数值范围波动较大，不能直接用树状数组去记录，其间必有许多0表现出极大的稀疏性，因此需要对原数组进行离散化。所谓离散化，即将原数组映射到1~N的数据范围，让数据的范围全部聚集在一起，减少空间浪费，有利于树状数组发挥。因为在该问题中我们不关心数据的绝对大小，仅关心数据的相对大小，所以可以离散化。离散化需要借助偏向的二分查找进行。
对于数组[1,3,2,4,1]，离散化后的结果是1,4,3,5,1，程序处理过程中树状数组的变化为（树状数组0位弃用）：
对于原数组 [1,4,3,5,1]从后往前遍历 1-&gt;5-&gt;3-&gt;4-&gt;1X    [0,0,0,0,0,0]   ret = 0 初始1    [0,1,1,0,1,0]   ret = 05    [0,1,1,0,1,1]   ret = 13    [0,1,1,1,2,1]   ret = 24    [0,1,1,1,3,1]   ret = 41    [0,2,2,1,4,1]   ret = 4最终逆序对即为4
// 树状数组class Trr &#123;    vector&lt;int&gt; trr;public:    static int lowbit(int a) &#123; return a &amp; -a; &#125;    Trr(const vector&lt;int&gt;&amp; arr) : trr(arr.size() + 1) &#123;        for (int i = 0; i &lt; arr.size(); ++i) &#123;            int t = i + 1;            while (t &lt; trr.size()) &#123;                trr[t] += arr[i];                t += lowbit(t);            &#125;        &#125;    &#125;    int query(int n) &#123; // from 1        int ret = 0;        while (n) &#123;            ret += trr[n];            n -= lowbit(n);        &#125;        return ret;    &#125;    void update(int pos, int diff) &#123; // from 1        while (pos &lt; trr.size()) &#123;            trr[pos] += diff;            pos += lowbit(pos);        &#125;    &#125;&#125;;class Solution &#123;public:    int reversePairs(vector&lt;int&gt;&amp; nums) &#123;        // 离散化(nlogn)        vector&lt;int&gt; tmp(nums);        sort(tmp.begin(), tmp.end());        for (auto&amp; e : nums)            e = lower_bound(tmp.begin(), tmp.end(), e) - tmp.begin() + 1;        // 树状数组统计逆序对(nlogn)        Trr trr(vector&lt;int&gt;(nums.size())); // 初始化全0        int ret = 0;        for (int i = nums.size() - 1; i &gt;= 0; --i) &#123;            trr.update(nums[i], 1);            ret += trr.query(nums[i] - 1);        &#125;        return ret;    &#125;&#125;;

小记
已知的树状数组的两种用途
原数组的下标作为索引，进行区间统计和修改
原数组的值作为下标，进行区间计数（本题）

83 删除排序链表中重复元素前序遍历class Solution &#123;public:    ListNode* deleteDuplicates(ListNode* head) &#123;        if(!head) return head;        ListNode* ptr = head-&gt;next;        while(ptr &amp;&amp; head-&gt;val == ptr-&gt;val) ptr = ptr-&gt;next;        // 下面俩方式效果一样        head-&gt;next = deleteDuplicates(ptr);        // head-&gt;next = ptr;        // deleteDuplicates(ptr);        return head;    &#125;&#125;;

后续遍历class Solution &#123;public:    ListNode* deleteDuplicates(ListNode* head) &#123;        if(!head) return head;        // 有点像并查集里的路径压缩        head-&gt;next = deleteDuplicates(head-&gt;next);        if(head-&gt;next &amp;&amp; head-&gt;val == head-&gt;next-&gt;val)            return head-&gt;next;        return head;    &#125;&#125;;

迭代法class Solution &#123;public:    ListNode* deleteDuplicates(ListNode* head) &#123;        if (!head) return head;        ListNode* cur = head;        while (cur-&gt;next) &#123;            if (cur-&gt;val == cur-&gt;next-&gt;val)                 cur-&gt;next = cur-&gt;next-&gt;next;            else                 cur = cur-&gt;next;        &#125;        return head;    &#125;&#125;;

迭代法：双指针class Solution &#123;public:    ListNode* deleteDuplicates(ListNode* head) &#123;        if (!head) return head;        ListNode* slow = head, *fast = head;        while(fast)&#123;            if(fast-&gt;val != slow-&gt;val)&#123;                slow-&gt;next = fast;                slow = slow-&gt;next;            &#125;            fast = fast-&gt;next;        &#125;        slow-&gt;next = nullptr; // 别忘了        return head;    &#125;&#125;;// 类似于数组去重，一模一样class Solution &#123;public:    int removeDuplicates(vector&lt;int&gt;&amp; nums) &#123;        if(nums.empty()) return 0;        int slow = 0, fast = 0;        while(fast &lt; nums.size())&#123;            if(nums[slow] != nums[fast])&#123;                nums[++slow] = nums[fast];            &#125;            ++fast;        &#125;        return slow + 1;    &#125;&#125;;

82 删除排序链表中的重复元素Ⅱ递归class Solution &#123;public:    int prev = INT_MAX;    ListNode* deleteDuplicates(ListNode* head) &#123;        if(!head || !head-&gt;next)&#123;            if(head) prev = head-&gt;val;            return head;        &#125;        head-&gt;next = deleteDuplicates(head-&gt;next);        while(head &amp;&amp; head-&gt;val == prev) // 如果要delete，在这里            head = head-&gt;next;        if(head &amp;&amp; head-&gt;val &lt; prev) // 小于号很重要，因为是递增链表，防止prev更新旧值            prev = head-&gt;val;        return head;    &#125;&#125;;

递归2(类似83后续遍历)class Solution &#123;public:    int prev = INT_MIN;    ListNode* deleteDuplicates(ListNode* head) &#123;        if(!head) return head;        // 有点像并查集里的路径压缩        head-&gt;next = deleteDuplicates(head-&gt;next);        if(head-&gt;next &amp;&amp; head-&gt;val == head-&gt;next-&gt;val)&#123;            prev = head-&gt;val;            return head-&gt;next-&gt;next;        &#125;        if(head-&gt;val == prev)            return head-&gt;next;        return head;    &#125;&#125;;

迭代class Solution &#123;public:    ListNode* deleteDuplicates(ListNode* head) &#123;        ListNode* dummy = new ListNode(INT_MAX, head);        ListNode* ptr = dummy;        while(ptr)&#123;            ListNode* cur = ptr-&gt;next;            while(cur &amp;&amp; cur-&gt;next &amp;&amp; cur-&gt;val == cur-&gt;next-&gt;val)&#123;                cur = cur-&gt;next;            &#125;            if(cur == ptr-&gt;next) // 下一步没重复，放心走                ptr = ptr-&gt;next;            else // 有重复 cur必不为nullptr，否则就是没重复那步                ptr-&gt;next = cur-&gt;next;        &#125;        return dummy-&gt;next;    &#125;&#125;;

1. 插入排序
只要注意每次判断比前面的大那就不需要回头
否则需要从头找合适的位置

ListNode* insertSort(ListNode* head) &#123;    if (!head || !head-&gt;next) return head;    ListNode dummy; dummy.next = head;    ListNode* prev = head;    ListNode* curr = head-&gt;next;    while (curr) &#123;        if (prev-&gt;val &lt;= curr-&gt;val) &#123;            prev = curr;            curr = curr-&gt;next;        &#125; else &#123;            ListNode* t = &amp;dummy;            while (t-&gt;next &amp;&amp; t-&gt;next-&gt;val &lt;= curr-&gt;val) t = t-&gt;next;            prev-&gt;next = curr-&gt;next;            curr-&gt;next = t-&gt;next;            t-&gt;next = curr;            curr = prev-&gt;next;        &#125;    &#125;    return dummy.next;&#125;

2. 归并排序
不论是主递归还是merge都要求两个链表以nullptr结尾
也就是在合适的地方断开

2.1 递归版本ListNode* mergeTwoList(ListNode* p2a, ListNode* p2b) &#123;    ListNode dummy;    ListNode* ptr = &amp;dummy;    while (p2a || p2b) &#123;        int a = p2a ? p2a-&gt;val : INT_MAX;        int b = p2b ? p2b-&gt;val : INT_MAX;        if (a &lt; b) &#123;            ptr-&gt;next = p2a;            p2a = p2a-&gt;next;        &#125;        else &#123;            ptr-&gt;next = p2b;            p2b = p2b-&gt;next;        &#125;        ptr = ptr-&gt;next; // 别忘了    &#125;    return dummy.next;&#125;ListNode* mergeSort(ListNode* head) &#123;    if (!head || !head-&gt;next) return head;    ListNode* slow = head, *fast = head;    while (fast) &#123; // 链表快慢指针有多种形式，要会灵活运用        fast = fast-&gt;next;        if(fast) fast = fast-&gt;next;        if(fast) slow = slow-&gt;next; // if(fast)：slow指向第一个链表的最后一位结点    &#125;    ListNode* head2 = slow-&gt;next;    slow-&gt;next = nullptr;    return mergeTwoList(mergeSort(head), mergeSort(head2));&#125;

2.2 非递归版本ListNode* mergeTwoList(ListNode* p2a, ListNode* p2b) &#123;    ListNode dummy;    ListNode* ptr = &amp;dummy;    while (p2a || p2b) &#123;        int a = p2a ? p2a-&gt;val : INT_MAX;        int b = p2b ? p2b-&gt;val : INT_MAX;        if (a &lt; b) &#123;            ptr-&gt;next = p2a;            p2a = p2a-&gt;next;        &#125;        else &#123;            ptr-&gt;next = p2b;            p2b = p2b-&gt;next;        &#125;        ptr = ptr-&gt;next; // 别忘了    &#125;    return dummy.next;&#125;ListNode* mergeSort(ListNode* head) &#123;    if (!head || !head-&gt;next) return head;    int n = 0;    ListNode* ptr = head;    while (ptr) &#123; // 统计链表长度        ++n;        ptr = ptr-&gt;next;    &#125;    ListNode dummy;    dummy.next = head;    ptr = &amp;dummy;    ListNode* prev, *l, *r, *t, *next; // 屮，5个指针    for (int w = 1; w &lt; n; w &lt;&lt;= 1) &#123;        prev = &amp;dummy;        l = dummy.next;        r = nullptr;        while (l) &#123;            // 第一个子链表的最后一个元素 注意：i从1开始            t = l;            for (int i = 1; i &lt; w &amp;&amp; t; ++i) t = t-&gt;next;            r = nullptr;            if (t) &#123;                r = t-&gt;next;                t-&gt;next = nullptr;            &#125;            // 第二个子链表的最后一个元素 注意：i从1开始            t = r;            for (int i = 1; i &lt; w &amp;&amp; t; ++i) t = t-&gt;next;            next = nullptr;            if (t) &#123;                next = t-&gt;next;                t-&gt;next = nullptr;            &#125;            // 合并子链表            ListNode* ret = mergeTwoList(l, r);            prev-&gt;next = ret;            // prev指向合并后的子链表的最后一个元素            while (prev-&gt;next) prev = prev-&gt;next;            l = next;        &#125;    &#125;    return dummy.next;&#125;

3. 快速排序
其实对于链表，由于不需要额外空间，归并排序其实很优秀了；快速排序由于需要选取pivot，选的不好，会变成n^2，而归并排序是稳定的nlogn
pivot的选取可以将中点节点移到链头充当pivot或者随机一个节点充当pivot，否则对于有序数列，会退化为n^2
由于无法采用l和r两边向中间靠拢的方式划分集合，只能采用单边形式，所以遇到“窄数据”或者都是一样值（窄特例化），也会退化为n^2

ListNode* quickSort(ListNode* head) &#123;    if (!head || !head-&gt;next) return head;    int pivot = head-&gt;val;    ListNode L, R;    ListNode* l = &amp;L, *r = &amp;R;    ListNode* ptr = head-&gt;next;    while (ptr) &#123;        if (ptr-&gt;val &lt;= pivot) &#123;            l-&gt;next = ptr;            l = l-&gt;next;        &#125;        else &#123;            r-&gt;next = ptr;            r = r-&gt;next;        &#125;        ptr = ptr-&gt;next;    &#125;    l-&gt;next = nullptr; // 断尾    r-&gt;next = nullptr; // 断尾    l = quickSort(L.next);    r = quickSort(R.next);    head-&gt;next = r;    if (!l) return head;    ListNode* t = l;    while (t-&gt;next) t = t-&gt;next;    t-&gt;next = head;    return l;&#125;

取中间作为pivot

ListNode* quickSort(ListNode* head) &#123;    if (!head || !head-&gt;next) return head;    ListNode* slow = head, *fast = head;    while (fast) &#123;        fast = fast-&gt;next;        if (fast) fast = fast-&gt;next;        if (fast) slow = slow-&gt;next;    &#125;    ListNode* newHead = slow-&gt;next;    slow-&gt;next = newHead-&gt;next;    newHead-&gt;next = head;    int pivot = newHead-&gt;val;    ListNode L, R;    ListNode* l = &amp;L, *r = &amp;R;    ListNode* ptr = newHead-&gt;next;    while (ptr) &#123;        if (ptr-&gt;val &lt;= pivot) &#123;            l-&gt;next = ptr;            l = l-&gt;next;        &#125;        else &#123;            r-&gt;next = ptr;            r = r-&gt;next;        &#125;        ptr = ptr-&gt;next;    &#125;    l-&gt;next = nullptr; // 断尾    r-&gt;next = nullptr; // 断尾    l = quickSort(L.next);    r = quickSort(R.next);    newHead-&gt;next = r;    if (!l) return newHead;    ListNode* t = l;    while (t-&gt;next) t = t-&gt;next;    t-&gt;next = newHead;    return l;&#125;

4. 辅助代码struct ListNode&#123;    int val;    ListNode* next;    ListNode(int _v = 0) :val(_v), next(nullptr) &#123;&#125;&#125;;ListNode* genList(int n, int range) &#123; // 数目， 分布范围    ListNode dummy;    ListNode* ptr = &amp;dummy;    for (int i = 0; i &lt; n; ++i) &#123;        int r = rand() % range;        ListNode* tmp = new ListNode(r);        ptr-&gt;next = tmp;        ptr = ptr-&gt;next;    &#125;    return dummy.next;&#125;void parseList(ListNode* p, bool show=true) &#123;    int ret = 0;    int cnt = 0;    while (p) &#123;        if(show) cout &lt;&lt; p-&gt;val &lt;&lt; &quot;\t&quot;;        p = p-&gt;next;        ++cnt;        if (show &amp;&amp; cnt / 10) &#123;            ret += cnt;            cnt = 0;            cout &lt;&lt; endl;        &#125;    &#125;    ret += cnt;    cout &lt;&lt; &quot;总计:&quot;&lt;&lt; ret &lt;&lt; endl;&#125;int main() &#123;    ListNode* ptr = genList(1000, 1000);    parseList(ptr, true);    // ptr = yourSort(ptr);    parseList(ptr, true);    return 0;&#125;
